  related:{identidade:["core","navegacao"],core:["identidade","navegacao"],navegacao:["core","identidade"],preco:["servicos","portal","contato","lead"],prazo:["servicos","portal","suporte"],servicos:["preco","prazo","portal","contato"],blogger:["seo","portal","suporte","personalizacao","seguranca"],seo:["blogger","portal","performance"],portal:["blogger","seo","servicos","preco"],suporte:["blogger","manutencao","contato"],contato:["whatsapp","email","lead","preco"],lead:["contato","preco"],privacidade:["seguranca","core"],seguranca:["privacidade","blogger"],performance:["seo","blogger"],personalizacao:["blogger","portal"],manutencao:["suporte","servicos"],voz:["core","robo"],robo:["voz","core"]}
