var KB=[{"id":"v3_capabilities","cat":"core","area":"core","type":"qa","priority":930,"q":"O que mudou no Nexus Brain V3?","aliases":["brain v3","nexus v3","o que mudou","nova versao","versão nova","versao v3"],"kw":["v3","brain","mudou","versao"],"answer":"No Brain V3 eu uso identidade fixa, grafo de conhecimento, BM25 local, n-gramas, fuzzy matching, slots, contexto, inferência simples de preço/prazo e registro de perguntas não respondidas."},{"id":"v3_graph","cat":"core","area":"core","type":"qa","priority":900,"q":"Você tem grafo de conhecimento?","aliases":["knowledge graph","grafo de conhecimento","grafo local","relacoes entre assuntos"],"kw":["grafo","conhecimento","relacoes"],"answer":"Sim. Eu organizo entidades como portal, Blogger, SEO, domínio, widgets, AdSense, robô e voz em um grafo local com relações entre elas."},{"id":"v3_bm25","cat":"core","area":"core","type":"qa","priority":890,"q":"Como você escolhe a melhor resposta?","aliases":["como escolhe resposta","motor de busca","bm25","ranking interno","score"],"kw":["bm25","score","ranking","resposta"],"answer":"Eu combino BM25 local, aliases, n-gramas, palavras-chave, intenção, categoria, prioridade e contexto recente para escolher a resposta mais provável."},{"id":"v3_slots","cat":"lead","area":"contato","type":"qa","priority":870,"q":"Você consegue entender dados do projeto?","aliases":["entende meu projeto","extrai dados","slot filling","dados do orçamento"],"kw":["projeto","dados","slot","orcamento"],"answer":"Sim. Eu tento extrair tipo de projeto, urgência, orçamento mencionado, prazo desejado, tecnologias e contato, tudo localmente no navegador."},{"id":"v3_estimate","cat":"preco","area":"preco","type":"qa","priority":880,"q":"Você consegue estimar preço e prazo?","aliases":["estimativa","calcular preço","calcular prazo","quanto fica e quanto demora"],"kw":["estimativa","preco","prazo","calcular"],"answer":"Consigo gerar uma estimativa local aproximada com base nas entidades detectadas. Ela não substitui orçamento real, mas ajuda a orientar o visitante."},{"id":"identity_name","cat":"identidade","type":"identity","priority":1000,"q":"Qual é o seu nome?","aliases":["qual seu nome","qual é seu nome","qual e seu nome","seu nome","como você se chama","como voce se chama","diga seu nome","fala seu nome","nome do assistente","nome do robô","nome do robo","quem é você","quem e voce","você sabe seu nome","voce sabe seu nome"],"kw":["nome","chama","assistente","nexus","robo"],"answer":"Meu nome é Nexus. Sou o assistente virtual deste site."},{"id":"identity_function","cat":"identidade","type":"identity","priority":980,"q":"Qual é a sua função?","aliases":["para que você serve","para que voce serve","o que você faz","o que voce faz","qual sua função","qual sua funcao"],"kw":["funcao","serve","faz","objetivo"],"answer":"Minha função é conversar com visitantes, responder dúvidas frequentes, orientar sobre serviços e realizar atendimento local com engenharia de software própria."},{"id":"identity_nature","cat":"identidade","type":"identity","priority":970,"q":"Você é uma inteligência artificial?","aliases":["você é ia","voce e ia","você pensa","voce pensa","você é chatgpt","voce e chatgpt"],"kw":["ia","inteligencia","artificial","chatgpt","pensa"],"answer":"Sou um assistente por atendimento por base de conhecimento. Sou um assistente de atendimento controlado como o ChatGPT; eu encontro a melhor resposta em uma base preparada."},{"id":"identity_creator","cat":"identidade","type":"identity","priority":950,"q":"Quem criou você?","aliases":["quem te criou","quem criou o nexus","quem fez você","quem fez voce","quem criou esse assistente"],"kw":["criou","fez","criador","nexus"],"answer":"Este assistente faz parte do projeto Nexus Widget Brain: um assistente para Blogger com base de conhecimento, voz do dispositivo e robô animado."},{"id":"core_001","cat":"core","area":"core","type":"qa","priority":720,"q":"Quem é você?","aliases":["o que voce e","voce e um robo","voce e humano","voce e bot","voce e uma ia","Quem é você?","Explique sobre Quem é você?","Tenho dúvida: quem é você?","Quero entender quem é você?","Pode me orientar sobre quem é você??","Me fale sobre quem é você?","No caso de quem é você?, como funciona?","Resumo sobre quem é você?"],"kw":["quem","voce","robo","bot","humano","assistente"],"answer":"Sou um assistente deste site. Funciono por atendimento por base de conhecimento: minhas respostas vêm de uma base preparada, sem conexão com servidores externos."},{"id":"core_002","cat":"core","area":"core","type":"qa","priority":720,"q":"Como você funciona?","aliases":["como voce trabalha","como funciona o chat","voce usa ia","tem inteligencia artificial","Como você funciona?","Explique sobre Como você funciona?","Tenho dúvida: como você funciona?","Quero entender como você funciona?","Pode me orientar sobre como você funciona??","Me fale sobre como você funciona?","No caso de como você funciona?, como funciona?","Resumo sobre como você funciona?"],"kw":["como","funciona","trabalha","ia","inteligencia"],"answer":"Comparo sua pergunta com uma base de atendimento aplicando normalização de texto e pontuação por similaridade. Quando não tenho confiança suficiente, mostro sugestões relacionadas."},{"id":"core_003","cat":"core","area":"core","type":"qa","priority":720,"q":"O que você sabe responder?","aliases":["quais assuntos","sobre o que voce fala","temas que voce conhece","o que voce sabe","O que você sabe responder?","Explique sobre O que você sabe responder?","Tenho dúvida: o que você sabe responder?","Quero entender o que você sabe responder?","Pode me orientar sobre o que você sabe responder??","Me fale sobre o que você sabe responder?","No caso de o que você sabe responder?, como funciona?","Resumo sobre o que você sabe responder?"],"kw":["assuntos","temas","topicos","sabe","responde"],"answer":"Posso falar sobre: serviços, preços, prazos, Blogger, SEO, portal de notícias, suporte, contato e privacidade."},{"id":"core_004","cat":"core","area":"core","type":"qa","priority":720,"q":"Ajuda","aliases":["help","menu","opcoes","o que perguntar","comandos","Ajuda","Explique sobre Ajuda","Tenho dúvida: ajuda","Quero entender ajuda","Pode me orientar sobre ajuda?","Me fale sobre ajuda","No caso de ajuda, como funciona?","Resumo sobre ajuda"],"kw":["ajuda","help","menu","opcoes"],"answer":"Você pode perguntar sobre preços, prazos, serviços, Blogger, SEO, portal de notícias, suporte ou contato. Tente \"quanto custa um portal\" ou \"qual o prazo\"."},{"id":"core_005","cat":"core","area":"core","type":"qa","priority":720,"q":"Você é confiável?","aliases":["voce e bom","voce acerta","voce funciona bem","Você é confiável?","Explique sobre Você é confiável?","Tenho dúvida: você é confiável?","Quero entender você é confiável?","Pode me orientar sobre você é confiável??","Me fale sobre você é confiável?","No caso de você é confiável?, como funciona?","Resumo sobre você é confiável?"],"kw":["confiavel","bom","acerta","correto"],"answer":"Sou uma ferramenta auxiliar. Minhas respostas vêm de uma base fixa. Para casos específicos ou orçamentos, recomendo falar diretamente com a equipe."},{"id":"core_006","cat":"core","area":"core","type":"qa","priority":720,"q":"Você guarda o que eu digito?","aliases":["voce salva conversas","grava o que eu falo","Você guarda o que eu digito?","Explique sobre Você guarda o que eu digito?","Tenho dúvida: você guarda o que eu digito?","Quero entender você guarda o que eu digito?","Pode me orientar sobre você guarda o que eu digito??","Me fale sobre você guarda o que eu digito?","No caso de você guarda o que eu digito?, como funciona?","Resumo sobre você guarda o que eu digito?"],"kw":["guarda","salva","grava","registra"],"answer":"O histórico é salvo localmente no seu navegador (localStorage), nunca enviado para servidores externos. Você pode apagar com o comando /limpar."},{"id":"core_007","cat":"core","area":"core","type":"qa","priority":720,"q":"Posso confiar nas informações?","aliases":["informacoes corretas","dados confiaveis","respostas exatas","Posso confiar nas informações?","Explique sobre Posso confiar nas informações?","Tenho dúvida: posso confiar nas informações?","Quero entender posso confiar nas informações?","Pode me orientar sobre posso confiar nas informações??","Me fale sobre posso confiar nas informações?","No caso de posso confiar nas informações?, como funciona?","Resumo sobre posso confiar nas informações?"],"kw":["confiar","correto","informacao","exato"],"answer":"As respostas refletem informações cadastradas previamente. Para valores, prazos e condições atualizadas, confirme pelo canal de contato."},{"id":"core_008","cat":"core","area":"core","type":"qa","priority":720,"q":"Qual sua versão?","aliases":["versao do chat","release","build","Qual sua versão?","Explique sobre Qual sua versão?","Tenho dúvida: qual sua versão?","Quero entender qual sua versão?","Pode me orientar sobre qual sua versão??","Me fale sobre qual sua versão?","No caso de qual sua versão?, como funciona?","Resumo sobre qual sua versão?"],"kw":["versao","version","build","release"],"answer":"Estou na versão NXWB 2.0 — assistente por atendimento por base de conhecimento."},{"id":"saud_001","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Olá","aliases":["oi","ola","opa","eai","hey","hello","hi","salve","Olá","Explique sobre Olá","Tenho dúvida: olá","Quero entender olá","Pode me orientar sobre olá?","Me fale sobre olá","No caso de olá, como funciona?","Resumo sobre olá"],"kw":["ola","oi","opa","hey","salve"],"answer":"Olá! Em que posso ajudar hoje?"},{"id":"saud_002","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Bom dia","aliases":["boa tarde","boa noite","bom dia tudo bem","Bom dia","Explique sobre Bom dia","Tenho dúvida: bom dia","Quero entender bom dia","Pode me orientar sobre bom dia?","Me fale sobre bom dia","No caso de bom dia, como funciona?","Resumo sobre bom dia"],"kw":["bom","dia","boa","tarde","noite"],"answer":"Olá! Tudo certo? Como posso ajudar?"},{"id":"saud_003","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Tudo bem?","aliases":["como vai","tudo certo","beleza","firmeza","Tudo bem?","Explique sobre Tudo bem?","Tenho dúvida: tudo bem?","Quero entender tudo bem?","Pode me orientar sobre tudo bem??","Me fale sobre tudo bem?","No caso de tudo bem?, como funciona?","Resumo sobre tudo bem?"],"kw":["tudo","bem","beleza","como","vai"],"answer":"Tudo certo por aqui! Conta o que você precisa."},{"id":"saud_004","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"E aí?","aliases":["e ai tudo bem","fala","suave","E aí?","Explique sobre E aí?","Tenho dúvida: e aí?","Quero entender e aí?","Pode me orientar sobre e aí??","Me fale sobre e aí?","No caso de e aí?, como funciona?","Resumo sobre e aí?"],"kw":["eai","fala","suave"],"answer":"E aí! No que posso ajudar?"},{"id":"saud_005","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Obrigado","aliases":["valeu","obg","agradecido","thanks","obrigada","grato","Obrigado","Explique sobre Obrigado","Tenho dúvida: obrigado","Quero entender obrigado","Pode me orientar sobre obrigado?","Me fale sobre obrigado","No caso de obrigado, como funciona?","Resumo sobre obrigado"],"kw":["obrigado","valeu","obg","agradecido","grato"],"answer":"Por nada! Se precisar de mais algo, é só perguntar."},{"id":"saud_006","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Muito obrigado","aliases":["muito obrigada","agradeco demais","Muito obrigado","Explique sobre Muito obrigado","Tenho dúvida: muito obrigado","Quero entender muito obrigado","Pode me orientar sobre muito obrigado?","Me fale sobre muito obrigado","No caso de muito obrigado, como funciona?","Resumo sobre muito obrigado"],"kw":["muito","obrigado","demais"],"answer":"Imagina! Estou aqui se precisar."},{"id":"saud_007","cat":"despedida","area":"saudacao","type":"qa","priority":690,"q":"Tchau","aliases":["ate logo","ate mais","falou","bye","xau","Tchau","Explique sobre Tchau","Tenho dúvida: tchau","Quero entender tchau","Pode me orientar sobre tchau?","Me fale sobre tchau","No caso de tchau, como funciona?","Resumo sobre tchau"],"kw":["tchau","ate","logo","falou","bye","xau"],"answer":"Até mais! Quando precisar, o chat estará aqui."},{"id":"saud_008","cat":"despedida","area":"saudacao","type":"qa","priority":690,"q":"Boa noite (despedida)","aliases":["boa noite ate amanha","vou dormir","Boa noite (despedida)","Explique sobre Boa noite (despedida)","Tenho dúvida: boa noite (despedida)","Quero entender boa noite (despedida)","Pode me orientar sobre boa noite (despedida)?","Me fale sobre boa noite (despedida)","No caso de boa noite (despedida), como funciona?","Resumo sobre boa noite (despedida)"],"kw":["boa","noite","amanha","dormir"],"answer":"Boa noite! Até a próxima."},{"id":"saud_009","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Você está aí?","aliases":["ola tem alguem","ola alguem","tem gente","Você está aí?","Explique sobre Você está aí?","Tenho dúvida: você está aí?","Quero entender você está aí?","Pode me orientar sobre você está aí??","Me fale sobre você está aí?","No caso de você está aí?, como funciona?","Resumo sobre você está aí?"],"kw":["esta","ai","alguem","gente"],"answer":"Estou sim! Pode mandar sua pergunta."},{"id":"saud_010","cat":"saudacao","area":"saudacao","type":"qa","priority":690,"q":"Bom te ver","aliases":["legal te encontrar","que bom","Bom te ver","Explique sobre Bom te ver","Tenho dúvida: bom te ver","Quero entender bom te ver","Pode me orientar sobre bom te ver?","Me fale sobre bom te ver","No caso de bom te ver, como funciona?","Resumo sobre bom te ver"],"kw":["bom","ver","encontrar","legal"],"answer":"Bom te ver por aqui! Como posso ajudar?"},{"id":"serv_001","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Quais serviços vocês oferecem?","aliases":["o que voces fazem","servicos disponiveis","lista de servicos","catalogo","Quais serviços vocês oferecem?","Explique sobre Quais serviços vocês oferecem?","Tenho dúvida: quais serviços vocês oferecem?","Quero entender quais serviços vocês oferecem?","Pode me orientar sobre quais serviços vocês oferecem??","Me fale sobre quais serviços vocês oferecem?","No caso de quais serviços vocês oferecem?, como funciona?","Resumo sobre quais serviços vocês oferecem?"],"kw":["servicos","oferecem","fazem","trabalho","catalogo"],"answer":"Os principais serviços incluem: criação de sites e portais no Blogger, otimização de SEO, configuração de domínio personalizado, design de layout responsivo, manutenção e suporte técnico."},{"id":"serv_002","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Vocês criam portais de notícias?","aliases":["fazem site de noticias","desenvolvem portal","montam jornal online","Vocês criam portais de notícias?","Explique sobre Vocês criam portais de notícias?","Tenho dúvida: vocês criam portais de notícias?","Quero entender vocês criam portais de notícias?","Pode me orientar sobre vocês criam portais de notícias??","Me fale sobre vocês criam portais de notícias?","No caso de vocês criam portais de notícias?, como funciona?","Resumo sobre vocês criam portais de notícias?"],"kw":["portal","noticias","criar","fazer","montar"],"answer":"Sim. Desenvolvemos portais de notícias completos no Blogger, com destaques, categorias, busca, autoria e SEO."},{"id":"serv_003","cat":"manutencao","area":"servicos","type":"qa","priority":520,"q":"Vocês fazem manutenção?","aliases":["suporte continuo","manutencao mensal","cuidam do site","manutencao do blogger","Vocês fazem manutenção?","Explique sobre Vocês fazem manutenção?","Tenho dúvida: vocês fazem manutenção?","Quero entender vocês fazem manutenção?","Pode me orientar sobre vocês fazem manutenção??","Me fale sobre vocês fazem manutenção?","No caso de vocês fazem manutenção?, como funciona?","Resumo sobre vocês fazem manutenção?"],"kw":["manutencao","cuidar","mensal","continuo"],"answer":"Sim. Há planos de manutenção que incluem atualizações de layout, ajustes de SEO, backup periódico e suporte para dúvidas."},{"id":"serv_004","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Trabalham com WordPress?","aliases":["fazem wordpress","tem wp","plataforma wordpress","desenvolvem wp","Trabalham com WordPress?","Explique sobre Trabalham com WordPress?","Tenho dúvida: trabalham com WordPress?","Quero entender trabalham com WordPress?","Pode me orientar sobre trabalham com WordPress??","Me fale sobre trabalham com WordPress?","No caso de trabalham com WordPress?, como funciona?","Resumo sobre trabalham com WordPress?"],"kw":["wordpress","wp","plataforma"],"answer":"O foco aqui é Blogger, por ser gratuito e estável. Para WordPress, fale pelo canal de contato para avaliarmos."},{"id":"serv_005","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Criam logo e identidade visual?","aliases":["design de logo","fazem logotipo","identidade visual","marca","Criam logo e identidade visual?","Explique sobre Criam logo e identidade visual?","Tenho dúvida: criam logo e identidade visual?","Quero entender criam logo e identidade visual?","Pode me orientar sobre criam logo e identidade visual??","Me fale sobre criam logo e identidade visual?","No caso de criam logo e identidade visual?, como funciona?","Resumo sobre criam logo e identidade visual?"],"kw":["logo","logotipo","identidade","design","marca"],"answer":"Identidade visual básica pode ser incluída no projeto. Para trabalho dedicado de marca, fale pelo contato."},{"id":"serv_006","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Fazem migração de site?","aliases":["migrar site","mudar de plataforma","transferir site","Fazem migração de site?","Explique sobre Fazem migração de site?","Tenho dúvida: fazem migração de site?","Quero entender fazem migração de site?","Pode me orientar sobre fazem migração de site??","Me fale sobre fazem migração de site?","No caso de fazem migração de site?, como funciona?","Resumo sobre fazem migração de site?"],"kw":["migracao","migrar","transferir","mudar"],"answer":"Sim. Realizamos migração de conteúdo, redirecionamentos 301 e preservação de SEO."},{"id":"serv_007","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Vocês fazem redação de conteúdo?","aliases":["escrevem artigos","produzem textos","copywriting","Vocês fazem redação de conteúdo?","Explique sobre Vocês fazem redação de conteúdo?","Tenho dúvida: vocês fazem redação de conteúdo?","Quero entender vocês fazem redação de conteúdo?","Pode me orientar sobre vocês fazem redação de conteúdo??","Me fale sobre vocês fazem redação de conteúdo?","No caso de vocês fazem redação de conteúdo?, como funciona?","Resumo sobre vocês fazem redação de conteúdo?"],"kw":["conteudo","redacao","artigos","textos","escrita"],"answer":"Produção de conteúdo pode ser contratada como serviço adicional ou em pacotes editoriais."},{"id":"serv_008","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Trabalham com Google AdSense?","aliases":["configuram adsense","monetizacao adsense","Trabalham com Google AdSense?","Explique sobre Trabalham com Google AdSense?","Tenho dúvida: trabalham com Google AdSense?","Quero entender trabalham com Google AdSense?","Pode me orientar sobre trabalham com Google AdSense??","Me fale sobre trabalham com Google AdSense?","No caso de trabalham com Google AdSense?, como funciona?","Resumo sobre trabalham com Google AdSense?"],"kw":["adsense","monetizar","anuncios"],"answer":"Sim. Fazemos integração e configuração de AdSense e otimização dos blocos de anúncios no template."},{"id":"serv_009","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Configuram domínio personalizado?","aliases":["ligam dominio proprio","configuracao de dominio","dominio no blogger","Configuram domínio personalizado?","Explique sobre Configuram domínio personalizado?","Tenho dúvida: configuram domínio personalizado?","Quero entender configuram domínio personalizado?","Pode me orientar sobre configuram domínio personalizado??","Me fale sobre configuram domínio personalizado?","No caso de configuram domínio personalizado?, como funciona?","Resumo sobre configuram domínio personalizado?"],"kw":["dominio","personalizado","proprio","dns"],"answer":"Sim. Realizamos toda a configuração de DNS para vincular seu domínio próprio ao Blogger."},{"id":"serv_010","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Fazem design responsivo?","aliases":["site mobile","adaptado para celular","responsivo","Fazem design responsivo?","Explique sobre Fazem design responsivo?","Tenho dúvida: fazem design responsivo?","Quero entender fazem design responsivo?","Pode me orientar sobre fazem design responsivo??","Me fale sobre fazem design responsivo?","No caso de fazem design responsivo?, como funciona?","Resumo sobre fazem design responsivo?"],"kw":["responsivo","mobile","celular","adaptado"],"answer":"Todos os projetos são entregues com layout responsivo, otimizado para celular, tablet e desktop."},{"id":"serv_011","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Vocês fazem integração com redes sociais?","aliases":["conectar redes","botoes sociais","integrar instagram","Vocês fazem integração com redes sociais?","Explique sobre Vocês fazem integração com redes sociais?","Tenho dúvida: vocês fazem integração com redes sociais?","Quero entender vocês fazem integração com redes sociais?","Pode me orientar sobre vocês fazem integração com redes sociais??","Me fale sobre vocês fazem integração com redes sociais?","No caso de vocês fazem integração com redes sociais?, como funciona?","Resumo sobre vocês fazem integração com redes sociais?"],"kw":["redes","sociais","instagram","facebook","integracao"],"answer":"Sim. Incluímos botões de compartilhamento, meta tags Open Graph e feeds quando aplicável."},{"id":"serv_012","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Trabalham com newsletter?","aliases":["email marketing","lista de emails","captura de leads","Trabalham com newsletter?","Explique sobre Trabalham com newsletter?","Tenho dúvida: trabalham com newsletter?","Quero entender trabalham com newsletter?","Pode me orientar sobre trabalham com newsletter??","Me fale sobre trabalham com newsletter?","No caso de trabalham com newsletter?, como funciona?","Resumo sobre trabalham com newsletter?"],"kw":["newsletter","email","marketing","lista"],"answer":"Configuramos formulários de inscrição. A entrega de e-mails é feita por ferramentas de terceiros (Mailchimp, Brevo etc.) sob escolha do cliente."},{"id":"serv_013","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Fazem ajustes pontuais?","aliases":["edicao rapida","pequenos ajustes","correcao pontual","Fazem ajustes pontuais?","Explique sobre Fazem ajustes pontuais?","Tenho dúvida: fazem ajustes pontuais?","Quero entender fazem ajustes pontuais?","Pode me orientar sobre fazem ajustes pontuais??","Me fale sobre fazem ajustes pontuais?","No caso de fazem ajustes pontuais?, como funciona?","Resumo sobre fazem ajustes pontuais?"],"kw":["ajuste","pontual","rapido","correcao"],"answer":"Sim. Ajustes pontuais podem ser cobrados por hora ou pacote, conforme o escopo."},{"id":"serv_014","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Atendem em todo o Brasil?","aliases":["atendimento nacional","onde atendem","regiao de atendimento","Atendem em todo o Brasil?","Explique sobre Atendem em todo o Brasil?","Tenho dúvida: atendem em todo o Brasil?","Quero entender atendem em todo o Brasil?","Pode me orientar sobre atendem em todo o Brasil??","Me fale sobre atendem em todo o Brasil?","No caso de atendem em todo o Brasil?, como funciona?","Resumo sobre atendem em todo o Brasil?"],"kw":["atendem","brasil","nacional","regiao","onde"],"answer":"Sim. O atendimento é 100% online, então atendemos qualquer região."},{"id":"serv_015","cat":"servicos","area":"servicos","type":"qa","priority":600,"q":"Fazem treinamento para o cliente usar o painel?","aliases":["ensinam a usar","treinamento blogger","aulas de uso","Fazem treinamento para o cliente usar o painel?","Explique sobre Fazem treinamento para o cliente usar o painel?","Tenho dúvida: fazem treinamento para o cliente usar o painel?","Quero entender fazem treinamento para o cliente usar o painel?","Pode me orientar sobre fazem treinamento para o cliente usar o painel??","Me fale sobre fazem treinamento para o cliente usar o painel?","No caso de fazem treinamento para o cliente usar o painel?, como funciona?","Resumo sobre fazem treinamento para o cliente usar o painel?"],"kw":["treinamento","ensinar","aulas","painel","usar"],"answer":"Sim. Após a entrega, oferecemos sessão de treinamento para o cliente operar o painel do Blogger com autonomia."},{"id":"prec_001","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Quanto custa criar um portal de notícias?","aliases":["valor de portal","preco site noticias","quanto custa portal blogger","orcamento portal","Quanto custa criar um portal de notícias?","Explique sobre Quanto custa criar um portal de notícias?","Tenho dúvida: quanto custa criar um portal de notícias?","Quero entender quanto custa criar um portal de notícias?","Pode me orientar sobre quanto custa criar um portal de notícias??","Me fale sobre quanto custa criar um portal de notícias?","No caso de quanto custa criar um portal de notícias?, como funciona?","Resumo sobre quanto custa criar um portal de notícias?"],"kw":["preco","valor","custa","orcamento","portal","quanto"],"answer":"O valor depende do layout, recursos, quantidade de seções e prazo. Posso encaminhar seu contato para um orçamento personalizado.","lead":true},{"id":"prec_002","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Tem plano fixo ou mensalidade?","aliases":["plano mensal","assinatura","mensalidade","planos fixos","Tem plano fixo ou mensalidade?","Explique sobre Tem plano fixo ou mensalidade?","Tenho dúvida: tem plano fixo ou mensalidade?","Quero entender tem plano fixo ou mensalidade?","Pode me orientar sobre tem plano fixo ou mensalidade??","Me fale sobre tem plano fixo ou mensalidade?","No caso de tem plano fixo ou mensalidade?, como funciona?","Resumo sobre tem plano fixo ou mensalidade?"],"kw":["plano","mensal","mensalidade","assinatura","fixo"],"answer":"Existem dois modelos: projeto único (pagamento fechado) e plano de manutenção mensal. Os valores variam conforme o escopo."},{"id":"prec_003","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Aceita parcelamento?","aliases":["parcelado","dividido","a prazo","pode parcelar","Aceita parcelamento?","Explique sobre Aceita parcelamento?","Tenho dúvida: aceita parcelamento?","Quero entender aceita parcelamento?","Pode me orientar sobre aceita parcelamento??","Me fale sobre aceita parcelamento?","No caso de aceita parcelamento?, como funciona?","Resumo sobre aceita parcelamento?"],"kw":["parcelamento","parcelar","dividir","parcelado"],"answer":"Geralmente é possível parcelar o valor do projeto. As condições exatas são fechadas no orçamento."},{"id":"prec_004","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Tem desconto?","aliases":["promocao","oferta","desconto","cupom","Tem desconto?","Explique sobre Tem desconto?","Tenho dúvida: tem desconto?","Quero entender tem desconto?","Pode me orientar sobre tem desconto??","Me fale sobre tem desconto?","No caso de tem desconto?, como funciona?","Resumo sobre tem desconto?"],"kw":["desconto","promocao","oferta","cupom"],"answer":"Promoções variam por período. Vale enviar contato para verificar condições atuais."},{"id":"prec_005","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Qual o valor mínimo de projeto?","aliases":["valor inicial","ticket minimo","minimo para fechar","Qual o valor mínimo de projeto?","Explique sobre Qual o valor mínimo de projeto?","Tenho dúvida: qual o valor mínimo de projeto?","Quero entender qual o valor mínimo de projeto?","Pode me orientar sobre qual o valor mínimo de projeto??","Me fale sobre qual o valor mínimo de projeto?","No caso de qual o valor mínimo de projeto?, como funciona?","Resumo sobre qual o valor mínimo de projeto?"],"kw":["minimo","inicial","ticket","partir"],"answer":"Há projetos de diferentes portes. Para saber a faixa inicial mais adequada ao seu caso, peça um orçamento.","lead":true},{"id":"prec_006","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Como funciona a forma de pagamento?","aliases":["formas de pagamento","como pago","meios de pagamento","Como funciona a forma de pagamento?","Explique sobre Como funciona a forma de pagamento?","Tenho dúvida: como funciona a forma de pagamento?","Quero entender como funciona a forma de pagamento?","Pode me orientar sobre como funciona a forma de pagamento??","Me fale sobre como funciona a forma de pagamento?","No caso de como funciona a forma de pagamento?, como funciona?","Resumo sobre como funciona a forma de pagamento?"],"kw":["pagamento","pago","forma","meios"],"answer":"Aceitamos Pix, transferência e cartão (parcelado). A primeira parcela costuma ser solicitada como entrada para início do projeto."},{"id":"prec_007","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Vocês cobram por hora?","aliases":["valor por hora","hora tecnica","cobranca por hora","Vocês cobram por hora?","Explique sobre Vocês cobram por hora?","Tenho dúvida: vocês cobram por hora?","Quero entender vocês cobram por hora?","Pode me orientar sobre vocês cobram por hora??","Me fale sobre vocês cobram por hora?","No caso de vocês cobram por hora?, como funciona?","Resumo sobre vocês cobram por hora?"],"kw":["hora","horas","tecnica","cobrar"],"answer":"Para ajustes pontuais, sim. Para projetos completos, o orçamento é fechado por escopo, não por hora."},{"id":"prec_008","cat":"preco","area":"preco","type":"qa","priority":640,"q":"O orçamento é gratuito?","aliases":["cobram pra fazer orcamento","tem custo orcamento","quanto custa o orcamento","O orçamento é gratuito?","Explique sobre O orçamento é gratuito?","Tenho dúvida: o orçamento é gratuito?","Quero entender o orçamento é gratuito?","Pode me orientar sobre o orçamento é gratuito??","Me fale sobre o orçamento é gratuito?","No caso de o orçamento é gratuito?, como funciona?","Resumo sobre o orçamento é gratuito?"],"kw":["orcamento","gratuito","cobram","custo"],"answer":"Sim, o orçamento inicial é gratuito e sem compromisso."},{"id":"prec_009","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Quanto custa apenas o SEO?","aliases":["preco do seo","valor seo","consultoria seo preco","Quanto custa apenas o SEO?","Explique sobre Quanto custa apenas o SEO?","Tenho dúvida: quanto custa apenas o SEO?","Quero entender quanto custa apenas o SEO?","Pode me orientar sobre quanto custa apenas o SEO??","Me fale sobre quanto custa apenas o SEO?","No caso de quanto custa apenas o SEO?, como funciona?","Resumo sobre quanto custa apenas o SEO?"],"kw":["preco","seo","consultoria","valor"],"answer":"O SEO pode ser contratado isolado ou em pacote com manutenção. O valor depende do escopo (técnico, conteúdo, link building).","lead":true},{"id":"prec_010","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Quanto custa migrar meu site?","aliases":["valor migracao","preco para mudar de plataforma","Quanto custa migrar meu site?","Explique sobre Quanto custa migrar meu site?","Tenho dúvida: quanto custa migrar meu site?","Quero entender quanto custa migrar meu site?","Pode me orientar sobre quanto custa migrar meu site??","Me fale sobre quanto custa migrar meu site?","No caso de quanto custa migrar meu site?, como funciona?","Resumo sobre quanto custa migrar meu site?"],"kw":["migrar","migracao","valor","preco"],"answer":"A migração é cobrada conforme o volume de conteúdo e a complexidade do site atual. Peça um orçamento detalhado.","lead":true},{"id":"prec_011","cat":"preco","area":"preco","type":"qa","priority":640,"q":"O preço inclui hospedagem?","aliases":["hospedagem inclusa","tem custo de hospedagem","servidor incluso","O preço inclui hospedagem?","Explique sobre O preço inclui hospedagem?","Tenho dúvida: o preço inclui hospedagem?","Quero entender o preço inclui hospedagem?","Pode me orientar sobre o preço inclui hospedagem??","Me fale sobre o preço inclui hospedagem?","No caso de o preço inclui hospedagem?, como funciona?","Resumo sobre o preço inclui hospedagem?"],"kw":["hospedagem","servidor","inclui","custo"],"answer":"Como usamos Blogger, a hospedagem é gratuita pelo Google. Custo adicional só existe se você optar por domínio próprio."},{"id":"prec_012","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Quanto custa o domínio?","aliases":["valor do dominio","preco dominio personalizado","Quanto custa o domínio?","Explique sobre Quanto custa o domínio?","Tenho dúvida: quanto custa o domínio?","Quero entender quanto custa o domínio?","Pode me orientar sobre quanto custa o domínio??","Me fale sobre quanto custa o domínio?","No caso de quanto custa o domínio?, como funciona?","Resumo sobre quanto custa o domínio?"],"kw":["dominio","preco","custa","valor"],"answer":"O domínio é pago diretamente a registradores (Registro.br, GoDaddy etc.), geralmente entre R$ 40 e R$ 80 por ano para .com.br."},{"id":"prec_013","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Posso pagar só uma parte agora?","aliases":["entrada","sinal","pagamento parcial","Posso pagar só uma parte agora?","Explique sobre Posso pagar só uma parte agora?","Tenho dúvida: posso pagar só uma parte agora?","Quero entender posso pagar só uma parte agora?","Pode me orientar sobre posso pagar só uma parte agora??","Me fale sobre posso pagar só uma parte agora?","No caso de posso pagar só uma parte agora?, como funciona?","Resumo sobre posso pagar só uma parte agora?"],"kw":["entrada","sinal","parcial","agora"],"answer":"Sim. O modelo padrão é entrada na contratação e saldo na entrega, podendo ser parcelado."},{"id":"prec_014","cat":"preco","area":"preco","type":"qa","priority":640,"q":"O valor varia muito entre projetos?","aliases":["preco varia","muda muito de projeto","O valor varia muito entre projetos?","Explique sobre O valor varia muito entre projetos?","Tenho dúvida: o valor varia muito entre projetos?","Quero entender o valor varia muito entre projetos?","Pode me orientar sobre o valor varia muito entre projetos??","Me fale sobre o valor varia muito entre projetos?","No caso de o valor varia muito entre projetos?, como funciona?","Resumo sobre o valor varia muito entre projetos?"],"kw":["varia","muda","depende"],"answer":"Sim. Cada projeto tem escopo, prazo e recursos próprios. Por isso o orçamento é sempre personalizado."},{"id":"prec_015","cat":"preco","area":"preco","type":"qa","priority":640,"q":"Vocês emitem nota fiscal?","aliases":["nf","nota fiscal","recibo","Vocês emitem nota fiscal?","Explique sobre Vocês emitem nota fiscal?","Tenho dúvida: vocês emitem nota fiscal?","Quero entender vocês emitem nota fiscal?","Pode me orientar sobre vocês emitem nota fiscal??","Me fale sobre vocês emitem nota fiscal?","No caso de vocês emitem nota fiscal?, como funciona?","Resumo sobre vocês emitem nota fiscal?"],"kw":["nota","fiscal","nf","recibo"],"answer":"Sim. Emitimos nota fiscal de serviço para projetos contratados."},{"id":"praz_001","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Qual o prazo de entrega?","aliases":["quanto tempo demora","em quantos dias fica pronto","prazo para entrega","Qual o prazo de entrega?","Explique sobre Qual o prazo de entrega?","Tenho dúvida: qual o prazo de entrega?","Quero entender qual o prazo de entrega?","Pode me orientar sobre qual o prazo de entrega??","Me fale sobre qual o prazo de entrega?","No caso de qual o prazo de entrega?, como funciona?","Resumo sobre qual o prazo de entrega?"],"kw":["prazo","tempo","demora","entrega","dias"],"answer":"O prazo médio fica entre 7 e 20 dias úteis, dependendo da complexidade. Para definições exatas, é necessário o orçamento."},{"id":"praz_002","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Dá pra fazer urgente?","aliases":["entrega rapida","tem urgencia","preciso urgente","express","Dá pra fazer urgente?","Explique sobre Dá pra fazer urgente?","Tenho dúvida: dá pra fazer urgente?","Quero entender dá pra fazer urgente?","Pode me orientar sobre dá pra fazer urgente??","Me fale sobre dá pra fazer urgente?","No caso de dá pra fazer urgente?, como funciona?","Resumo sobre dá pra fazer urgente?"],"kw":["urgente","rapido","pressa","urgencia","express"],"answer":"Projetos urgentes podem ser avaliados conforme disponibilidade da agenda e podem ter acréscimo."},{"id":"praz_003","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Quando começa o projeto?","aliases":["inicio do trabalho","comeca quando","data inicio","Quando começa o projeto?","Explique sobre Quando começa o projeto?","Tenho dúvida: quando começa o projeto?","Quero entender quando começa o projeto?","Pode me orientar sobre quando começa o projeto??","Me fale sobre quando começa o projeto?","No caso de quando começa o projeto?, como funciona?","Resumo sobre quando começa o projeto?"],"kw":["comeca","inicio","iniciar","comecar"],"answer":"O projeto inicia após a aprovação do orçamento e o pagamento da entrada acordada."},{"id":"praz_004","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Qual o prazo para SEO trazer resultado?","aliases":["quando aparece no google","prazo seo","tempo seo","Qual o prazo para SEO trazer resultado?","Explique sobre Qual o prazo para SEO trazer resultado?","Tenho dúvida: qual o prazo para SEO trazer resultado?","Quero entender qual o prazo para SEO trazer resultado?","Pode me orientar sobre qual o prazo para SEO trazer resultado??","Me fale sobre qual o prazo para SEO trazer resultado?","No caso de qual o prazo para SEO trazer resultado?, como funciona?","Resumo sobre qual o prazo para SEO trazer resultado?"],"kw":["seo","resultado","aparece","google","tempo"],"answer":"SEO traz resultados consistentes a partir de 3 a 6 meses. A indexação inicial costuma ocorrer em dias."},{"id":"praz_005","cat":"manutencao","area":"prazo","type":"qa","priority":520,"q":"Qual o prazo de manutenção mensal?","aliases":["atendimento mensal","prazo manutencao","Qual o prazo de manutenção mensal?","Explique sobre Qual o prazo de manutenção mensal?","Tenho dúvida: qual o prazo de manutenção mensal?","Quero entender qual o prazo de manutenção mensal?","Pode me orientar sobre qual o prazo de manutenção mensal??","Me fale sobre qual o prazo de manutenção mensal?","No caso de qual o prazo de manutenção mensal?, como funciona?","Resumo sobre qual o prazo de manutenção mensal?"],"kw":["manutencao","mensal","prazo"],"answer":"A manutenção mensal é contínua. Chamados são atendidos em até 1 a 3 dias úteis, conforme prioridade."},{"id":"praz_006","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Tem prazo para revisões?","aliases":["quantas revisoes","rounds de ajuste","correcoes incluidas","Tem prazo para revisões?","Explique sobre Tem prazo para revisões?","Tenho dúvida: tem prazo para revisões?","Quero entender tem prazo para revisões?","Pode me orientar sobre tem prazo para revisões??","Me fale sobre tem prazo para revisões?","No caso de tem prazo para revisões?, como funciona?","Resumo sobre tem prazo para revisões?"],"kw":["revisoes","revisao","ajustes","rounds"],"answer":"O escopo padrão inclui um número definido de revisões. Ajustes além disso são cobrados separadamente."},{"id":"praz_007","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Posso acompanhar o andamento?","aliases":["ver progresso","status do projeto","andamento","Posso acompanhar o andamento?","Explique sobre Posso acompanhar o andamento?","Tenho dúvida: posso acompanhar o andamento?","Quero entender posso acompanhar o andamento?","Pode me orientar sobre posso acompanhar o andamento??","Me fale sobre posso acompanhar o andamento?","No caso de posso acompanhar o andamento?, como funciona?","Resumo sobre posso acompanhar o andamento?"],"kw":["acompanhar","andamento","progresso","status"],"answer":"Sim. Enviamos atualizações periódicas e disponibilizamos prévia em ambiente de testes."},{"id":"praz_008","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"O prazo conta corridos ou úteis?","aliases":["dias uteis ou corridos","prazo em dias","tipo de dias","O prazo conta corridos ou úteis?","Explique sobre O prazo conta corridos ou úteis?","Tenho dúvida: o prazo conta corridos ou úteis?","Quero entender o prazo conta corridos ou úteis?","Pode me orientar sobre o prazo conta corridos ou úteis??","Me fale sobre o prazo conta corridos ou úteis?","No caso de o prazo conta corridos ou úteis?, como funciona?","Resumo sobre o prazo conta corridos ou úteis?"],"kw":["dias","uteis","corridos","contagem"],"answer":"Os prazos são informados em dias úteis, salvo se especificado o contrário."},{"id":"praz_009","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Se eu demorar a responder, o prazo continua?","aliases":["prazo se eu sumir","demorei a responder","pausa no projeto","Se eu demorar a responder, o prazo continua?","Explique sobre Se eu demorar a responder, o prazo continua?","Tenho dúvida: se eu demorar a responder, o prazo continua?","Quero entender se eu demorar a responder, o prazo continua?","Pode me orientar sobre se eu demorar a responder, o prazo continua??","Me fale sobre se eu demorar a responder, o prazo continua?","No caso de se eu demorar a responder, o prazo continua?, como funciona?","Resumo sobre se eu demorar a responder, o prazo continua?"],"kw":["demorar","responder","pausa","adiar"],"answer":"O cronograma é ajustado conforme retornos do cliente. Atrasos de aprovação podem postergar a entrega."},{"id":"praz_010","cat":"prazo","area":"prazo","type":"qa","priority":590,"q":"Qual o prazo de ajustes pós-entrega?","aliases":["garantia","suporte pos entrega","correcao apos entrega","Qual o prazo de ajustes pós-entrega?","Explique sobre Qual o prazo de ajustes pós-entrega?","Tenho dúvida: qual o prazo de ajustes pós-entrega?","Quero entender qual o prazo de ajustes pós-entrega?","Pode me orientar sobre qual o prazo de ajustes pós-entrega??","Me fale sobre qual o prazo de ajustes pós-entrega?","No caso de qual o prazo de ajustes pós-entrega?, como funciona?","Resumo sobre qual o prazo de ajustes pós-entrega?"],"kw":["garantia","ajustes","pos","entrega"],"answer":"Há um período de garantia para correções de erros após a entrega, geralmente de 15 a 30 dias."},{"id":"blog_001","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Por que usar Blogger?","aliases":["vantagens do blogger","porque blogger","blogger e bom","Por que usar Blogger?","Explique sobre Por que usar Blogger?","Tenho dúvida: por que usar Blogger?","Quero entender por que usar Blogger?","Pode me orientar sobre por que usar Blogger??","Me fale sobre por que usar Blogger?","No caso de por que usar Blogger?, como funciona?","Resumo sobre por que usar Blogger?"],"kw":["blogger","vantagem","porque","usar"],"answer":"Blogger é gratuito, hospedado pelo Google, estável, suporta domínio personalizado e permite personalização total via XML."},{"id":"blog_002","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Posso usar meu próprio domínio no Blogger?","aliases":["dominio personalizado","dominio proprio blogger","colocar dominio","Posso usar meu próprio domínio no Blogger?","Explique sobre Posso usar meu próprio domínio no Blogger?","Tenho dúvida: posso usar meu próprio domínio no Blogger?","Quero entender posso usar meu próprio domínio no Blogger?","Pode me orientar sobre posso usar meu próprio domínio no Blogger??","Me fale sobre posso usar meu próprio domínio no Blogger?","No caso de posso usar meu próprio domínio no Blogger?, como funciona?","Resumo sobre posso usar meu próprio domínio no Blogger?"],"kw":["dominio","personalizado","proprio","url"],"answer":"Sim. Vincula-se qualquer domínio próprio via DNS. O processo é gratuito."},{"id":"blog_003","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Blogger aceita monetização?","aliases":["adsense blogger","ganhar dinheiro blogger","monetizar","Blogger aceita monetização?","Explique sobre Blogger aceita monetização?","Tenho dúvida: blogger aceita monetização?","Quero entender blogger aceita monetização?","Pode me orientar sobre blogger aceita monetização??","Me fale sobre blogger aceita monetização?","No caso de blogger aceita monetização?, como funciona?","Resumo sobre blogger aceita monetização?"],"kw":["monetizacao","adsense","ganhar","dinheiro","monetizar"],"answer":"Sim, integra-se ao Google AdSense e aceita outras redes via inserção de código no template."},{"id":"blog_004","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Como instalo um template XML no Blogger?","aliases":["upload template blogger","instalar tema xml","como colocar xml","Como instalo um template XML no Blogger?","Explique sobre Como instalo um template XML no Blogger?","Tenho dúvida: como instalo um template XML no Blogger?","Quero entender como instalo um template XML no Blogger?","Pode me orientar sobre como instalo um template XML no Blogger??","Me fale sobre como instalo um template XML no Blogger?","No caso de como instalo um template XML no Blogger?, como funciona?","Resumo sobre como instalo um template XML no Blogger?"],"kw":["instalar","template","tema","xml","upload"],"answer":"Painel: Tema → seta ao lado de Personalizar → Restaurar → upload do XML. Faça backup do tema atual antes."},{"id":"blog_005","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Blogger tem limite de postagens?","aliases":["limite de posts","maximo postagens","quantos posts","Blogger tem limite de postagens?","Explique sobre Blogger tem limite de postagens?","Tenho dúvida: blogger tem limite de postagens?","Quero entender blogger tem limite de postagens?","Pode me orientar sobre blogger tem limite de postagens??","Me fale sobre blogger tem limite de postagens?","No caso de blogger tem limite de postagens?, como funciona?","Resumo sobre blogger tem limite de postagens?"],"kw":["limite","maximo","postagens","posts"],"answer":"Não há limite prático de quantidade. Os limites são por tamanho do post e por armazenamento de imagens."},{"id":"blog_006","cat":"seguranca","area":"blogger","type":"qa","priority":530,"q":"Posso ter HTTPS no Blogger?","aliases":["ssl blogger","certificado","seguranca https","Posso ter HTTPS no Blogger?","Explique sobre Posso ter HTTPS no Blogger?","Tenho dúvida: posso ter HTTPS no Blogger?","Quero entender posso ter HTTPS no Blogger?","Pode me orientar sobre posso ter HTTPS no Blogger??","Me fale sobre posso ter HTTPS no Blogger?","No caso de posso ter HTTPS no Blogger?, como funciona?","Resumo sobre posso ter HTTPS no Blogger?"],"kw":["https","ssl","certificado","seguro"],"answer":"Sim. Blogger oferece HTTPS gratuito mesmo para domínios personalizados."},{"id":"blog_007","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Como faço backup do tema?","aliases":["salvar tema","exportar template","Como faço backup do tema?","Explique sobre Como faço backup do tema?","Tenho dúvida: como faço backup do tema?","Quero entender como faço backup do tema?","Pode me orientar sobre como faço backup do tema??","Me fale sobre como faço backup do tema?","No caso de como faço backup do tema?, como funciona?","Resumo sobre como faço backup do tema?"],"kw":["backup","tema","template","salvar"],"answer":"Tema → seta ao lado de Personalizar → Fazer backup. Isso gera um arquivo XML do template atual."},{"id":"blog_008","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Como exporto as postagens?","aliases":["backup posts","exportar conteudo","sair do blogger","Como exporto as postagens?","Explique sobre Como exporto as postagens?","Tenho dúvida: como exporto as postagens?","Quero entender como exporto as postagens?","Pode me orientar sobre como exporto as postagens??","Me fale sobre como exporto as postagens?","No caso de como exporto as postagens?, como funciona?","Resumo sobre como exporto as postagens?"],"kw":["exportar","postagens","backup","conteudo"],"answer":"Configurações → Gerenciar blog → Fazer backup do conteúdo. Gera arquivo XML com todas as postagens."},{"id":"blog_009","cat":"seo","area":"blogger","type":"qa","priority":570,"q":"Blogger é bom para SEO?","aliases":["blogger ranqueia","blogger google","seo blogger","Blogger é bom para SEO?","Explique sobre Blogger é bom para SEO?","Tenho dúvida: blogger é bom para SEO?","Quero entender blogger é bom para SEO?","Pode me orientar sobre blogger é bom para SEO??","Me fale sobre blogger é bom para SEO?","No caso de blogger é bom para SEO?, como funciona?","Resumo sobre blogger é bom para SEO?"],"kw":["blogger","seo","ranquear","google"],"answer":"Sim. Com template bem estruturado, Blogger ranqueia bem por ser indexável e leve. O conteúdo é o fator decisivo."},{"id":"blog_010","cat":"personalizacao","area":"blogger","type":"qa","priority":520,"q":"Posso adicionar JavaScript no Blogger?","aliases":["injetar js","codigo personalizado blogger","script no template","Posso adicionar JavaScript no Blogger?","Explique sobre Posso adicionar JavaScript no Blogger?","Tenho dúvida: posso adicionar JavaScript no Blogger?","Quero entender posso adicionar JavaScript no Blogger?","Pode me orientar sobre posso adicionar JavaScript no Blogger??","Me fale sobre posso adicionar JavaScript no Blogger?","No caso de posso adicionar JavaScript no Blogger?, como funciona?","Resumo sobre posso adicionar JavaScript no Blogger?"],"kw":["javascript","js","script","codigo"],"answer":"Sim. JS pode ser adicionado ao template XML ou via gadget HTML/JavaScript."},{"id":"blog_011","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"O que são widgets no Blogger?","aliases":["o que e gadget","widgets blogger","componentes","O que são widgets no Blogger?","Explique sobre O que são widgets no Blogger?","Tenho dúvida: o que são widgets no Blogger?","Quero entender o que são widgets no Blogger?","Pode me orientar sobre o que são widgets no Blogger??","Me fale sobre o que são widgets no Blogger?","No caso de o que são widgets no Blogger?, como funciona?","Resumo sobre o que são widgets no Blogger?"],"kw":["widget","gadget","componente"],"answer":"Widgets (ou gadgets) são blocos modulares (HTML, Lista, Marcadores, Pesquisa etc.) que compõem a estrutura do blog."},{"id":"blog_012","cat":"personalizacao","area":"blogger","type":"qa","priority":520,"q":"Posso personalizar o template?","aliases":["mudar layout","editar tema","customizar","Posso personalizar o template?","Explique sobre Posso personalizar o template?","Tenho dúvida: posso personalizar o template?","Quero entender posso personalizar o template?","Pode me orientar sobre posso personalizar o template??","Me fale sobre posso personalizar o template?","No caso de posso personalizar o template?, como funciona?","Resumo sobre posso personalizar o template?"],"kw":["personalizar","customizar","editar","layout"],"answer":"Sim, totalmente. Pelo editor de tema, é possível editar HTML, CSS e estrutura do XML."},{"id":"blog_013","cat":"performance","area":"blogger","type":"qa","priority":520,"q":"Blogger sai do ar?","aliases":["blogger fica fora do ar","estabilidade","uptime","Blogger sai do ar?","Explique sobre Blogger sai do ar?","Tenho dúvida: blogger sai do ar?","Quero entender blogger sai do ar?","Pode me orientar sobre blogger sai do ar??","Me fale sobre blogger sai do ar?","No caso de blogger sai do ar?, como funciona?","Resumo sobre blogger sai do ar?"],"kw":["ar","fora","estabilidade","uptime","instavel"],"answer":"Blogger é hospedado pela infraestrutura do Google. A estabilidade é alta, com indisponibilidades raras."},{"id":"blog_014","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Posso ter vários autores?","aliases":["multi autor","varios escritores","equipe editorial","Posso ter vários autores?","Explique sobre Posso ter vários autores?","Tenho dúvida: posso ter vários autores?","Quero entender posso ter vários autores?","Pode me orientar sobre posso ter vários autores??","Me fale sobre posso ter vários autores?","No caso de posso ter vários autores?, como funciona?","Resumo sobre posso ter vários autores?"],"kw":["autores","multiplos","equipe","escritores"],"answer":"Sim. Configurações → Permissões → Convidar autores. Suporta editores, administradores e leitores."},{"id":"blog_015","cat":"blogger","area":"blogger","type":"qa","priority":580,"q":"Blogger tem comentários nativos?","aliases":["comentario blogger","sistema de comentarios","Blogger tem comentários nativos?","Explique sobre Blogger tem comentários nativos?","Tenho dúvida: blogger tem comentários nativos?","Quero entender blogger tem comentários nativos?","Pode me orientar sobre blogger tem comentários nativos??","Me fale sobre blogger tem comentários nativos?","No caso de blogger tem comentários nativos?, como funciona?","Resumo sobre blogger tem comentários nativos?"],"kw":["comentarios","comentario","nativos"],"answer":"Sim. Há sistema nativo, com moderação. Também é possível integrar Disqus ou Facebook Comments."},{"id":"seo_001","cat":"seo","area":"seo","type":"qa","priority":570,"q":"O portal já vem otimizado para SEO?","aliases":["tem seo","site otimizado","blogger com seo","O portal já vem otimizado para SEO?","Explique sobre O portal já vem otimizado para SEO?","Tenho dúvida: o portal já vem otimizado para SEO?","Quero entender o portal já vem otimizado para SEO?","Pode me orientar sobre o portal já vem otimizado para SEO??","Me fale sobre o portal já vem otimizado para SEO?","No caso de o portal já vem otimizado para SEO?, como funciona?","Resumo sobre o portal já vem otimizado para SEO?"],"kw":["seo","otimizacao","google","indexacao"],"answer":"Sim. O portal inclui estrutura de headings, meta tags, dados estruturados, links internos e otimização de carregamento."},{"id":"seo_002","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Vocês fazem SEO contínuo?","aliases":["otimizar com frequencia","seo mensal","consultoria seo","Vocês fazem SEO contínuo?","Explique sobre Vocês fazem SEO contínuo?","Tenho dúvida: vocês fazem SEO contínuo?","Quero entender vocês fazem SEO contínuo?","Pode me orientar sobre vocês fazem SEO contínuo??","Me fale sobre vocês fazem SEO contínuo?","No caso de vocês fazem SEO contínuo?, como funciona?","Resumo sobre vocês fazem SEO contínuo?"],"kw":["continuo","mensal","consultoria","seo"],"answer":"Sim. SEO contínuo inclui análise de palavras-chave, ajustes técnicos, monitoramento de posições e relatório periódico."},{"id":"seo_003","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Em quanto tempo aparece no Google?","aliases":["indexar site","aparecer no google","tempo indexacao","Em quanto tempo aparece no Google?","Explique sobre Em quanto tempo aparece no Google?","Tenho dúvida: em quanto tempo aparece no Google?","Quero entender em quanto tempo aparece no Google?","Pode me orientar sobre em quanto tempo aparece no Google??","Me fale sobre em quanto tempo aparece no Google?","No caso de em quanto tempo aparece no Google?, como funciona?","Resumo sobre em quanto tempo aparece no Google?"],"kw":["indexar","indexacao","aparece","google","pesquisa"],"answer":"A indexação inicial costuma ocorrer em poucos dias. Bom posicionamento depende de conteúdo, autoridade e tempo (3 a 6 meses)."},{"id":"seo_004","cat":"seo","area":"seo","type":"qa","priority":570,"q":"O que são meta tags?","aliases":["o que sao metatags","tag de descricao","meta description","O que são meta tags?","Explique sobre O que são meta tags?","Tenho dúvida: o que são meta tags?","Quero entender o que são meta tags?","Pode me orientar sobre o que são meta tags??","Me fale sobre o que são meta tags?","No caso de o que são meta tags?, como funciona?","Resumo sobre o que são meta tags?"],"kw":["meta","tags","metatags","descricao","title"],"answer":"Meta tags são marcações no HTML que descrevem o conteúdo para buscadores e redes sociais. Principais: title, description e Open Graph."},{"id":"seo_005","cat":"seo","area":"seo","type":"qa","priority":570,"q":"O que são dados estruturados?","aliases":["schema","rich snippets","json ld","O que são dados estruturados?","Explique sobre O que são dados estruturados?","Tenho dúvida: o que são dados estruturados?","Quero entender o que são dados estruturados?","Pode me orientar sobre o que são dados estruturados??","Me fale sobre o que são dados estruturados?","No caso de o que são dados estruturados?, como funciona?","Resumo sobre o que são dados estruturados?"],"kw":["estruturados","schema","snippets","jsonld"],"answer":"Dados estruturados (schema.org) descrevem semanticamente o conteúdo (artigo, autor, data) e ajudam buscadores a entender e exibir trechos ricos."},{"id":"seo_006","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Como funciona o sitemap?","aliases":["mapa do site","xml sitemap","sitemap blogger","Como funciona o sitemap?","Explique sobre Como funciona o sitemap?","Tenho dúvida: como funciona o sitemap?","Quero entender como funciona o sitemap?","Pode me orientar sobre como funciona o sitemap??","Me fale sobre como funciona o sitemap?","No caso de como funciona o sitemap?, como funciona?","Resumo sobre como funciona o sitemap?"],"kw":["sitemap","mapa","xml"],"answer":"O Blogger gera sitemap automaticamente. O envio ao Google Search Console acelera a descoberta de URLs."},{"id":"seo_007","cat":"seo","area":"seo","type":"qa","priority":570,"q":"O que é Search Console?","aliases":["google search console","painel do google","gsc","O que é Search Console?","Explique sobre O que é Search Console?","Tenho dúvida: o que é Search Console?","Quero entender o que é Search Console?","Pode me orientar sobre o que é Search Console??","Me fale sobre o que é Search Console?","No caso de o que é Search Console?, como funciona?","Resumo sobre o que é Search Console?"],"kw":["search","console","gsc","painel"],"answer":"Ferramenta gratuita do Google para monitorar indexação, performance e erros de SEO do site."},{"id":"seo_008","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Como melhorar o ranking?","aliases":["rankear no google","subir posicao","melhorar busca","Como melhorar o ranking?","Explique sobre Como melhorar o ranking?","Tenho dúvida: como melhorar o ranking?","Quero entender como melhorar o ranking?","Pode me orientar sobre como melhorar o ranking??","Me fale sobre como melhorar o ranking?","No caso de como melhorar o ranking?, como funciona?","Resumo sobre como melhorar o ranking?"],"kw":["ranking","rankear","posicao","subir"],"answer":"Combinação de: conteúdo relevante, estrutura técnica correta, velocidade, links internos consistentes e autoridade externa (backlinks)."},{"id":"seo_009","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Backlinks são importantes?","aliases":["link externo","autoridade","linkbuilding","Backlinks são importantes?","Explique sobre Backlinks são importantes?","Tenho dúvida: backlinks são importantes?","Quero entender backlinks são importantes?","Pode me orientar sobre backlinks são importantes??","Me fale sobre backlinks são importantes?","No caso de backlinks são importantes?, como funciona?","Resumo sobre backlinks são importantes?"],"kw":["backlink","autoridade","linkbuilding","externos"],"answer":"Sim. Backlinks de sites relevantes aumentam a autoridade percebida do domínio."},{"id":"seo_010","cat":"seo","area":"seo","type":"qa","priority":570,"q":"O que é SEO técnico?","aliases":["seo tecnico","aspectos tecnicos","otimizacao tecnica","O que é SEO técnico?","Explique sobre O que é SEO técnico?","Tenho dúvida: o que é SEO técnico?","Quero entender o que é SEO técnico?","Pode me orientar sobre o que é SEO técnico??","Me fale sobre o que é SEO técnico?","No caso de o que é SEO técnico?, como funciona?","Resumo sobre o que é SEO técnico?"],"kw":["tecnico","tecnica","onpage"],"answer":"SEO técnico engloba velocidade, indexabilidade, estrutura de URL, mobile-friendly, schema, canonical e arquitetura interna."},{"id":"seo_011","cat":"performance","area":"seo","type":"qa","priority":520,"q":"Velocidade do site importa?","aliases":["site rapido seo","performance seo","core web vitals","Velocidade do site importa?","Explique sobre Velocidade do site importa?","Tenho dúvida: velocidade do site importa?","Quero entender velocidade do site importa?","Pode me orientar sobre velocidade do site importa??","Me fale sobre velocidade do site importa?","No caso de velocidade do site importa?, como funciona?","Resumo sobre velocidade do site importa?"],"kw":["velocidade","rapido","performance","vitals"],"answer":"Sim. Velocidade e Core Web Vitals afetam diretamente posicionamento e taxa de retenção."},{"id":"seo_012","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Como escolher palavras-chave?","aliases":["keyword research","pesquisa de palavras","escolher termos","Como escolher palavras-chave?","Explique sobre Como escolher palavras-chave?","Tenho dúvida: como escolher palavras-chave?","Quero entender como escolher palavras-chave?","Pode me orientar sobre como escolher palavras-chave??","Me fale sobre como escolher palavras-chave?","No caso de como escolher palavras-chave?, como funciona?","Resumo sobre como escolher palavras-chave?"],"kw":["palavras","chave","keyword","termos"],"answer":"Avaliando volume de busca, intenção, dificuldade de concorrência e relevância para o seu nicho."},{"id":"seo_013","cat":"seo","area":"seo","type":"qa","priority":570,"q":"SEO local existe?","aliases":["seo regional","negocio local google","google meu negocio","SEO local existe?","Explique sobre SEO local existe?","Tenho dúvida: sEO local existe?","Quero entender sEO local existe?","Pode me orientar sobre sEO local existe??","Me fale sobre sEO local existe?","No caso de sEO local existe?, como funciona?","Resumo sobre sEO local existe?"],"kw":["local","regional","negocio","perto"],"answer":"Sim. SEO local foca em buscas com intenção geográfica e usa Google Meu Negócio como peça central."},{"id":"seo_014","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Conteúdo duplicado prejudica?","aliases":["texto repetido seo","conteudo igual","Conteúdo duplicado prejudica?","Explique sobre Conteúdo duplicado prejudica?","Tenho dúvida: conteúdo duplicado prejudica?","Quero entender conteúdo duplicado prejudica?","Pode me orientar sobre conteúdo duplicado prejudica??","Me fale sobre conteúdo duplicado prejudica?","No caso de conteúdo duplicado prejudica?, como funciona?","Resumo sobre conteúdo duplicado prejudica?"],"kw":["duplicado","repetido","copia","igual"],"answer":"Sim. Conteúdo duplicado dispersa autoridade e pode reduzir o ranqueamento. Use canonicals ou reescreva."},{"id":"seo_015","cat":"seo","area":"seo","type":"qa","priority":570,"q":"Vocês fazem relatório de SEO?","aliases":["relatorio mensal seo","metricas seo","Vocês fazem relatório de SEO?","Explique sobre Vocês fazem relatório de SEO?","Tenho dúvida: vocês fazem relatório de SEO?","Quero entender vocês fazem relatório de SEO?","Pode me orientar sobre vocês fazem relatório de SEO??","Me fale sobre vocês fazem relatório de SEO?","No caso de vocês fazem relatório de SEO?, como funciona?","Resumo sobre vocês fazem relatório de SEO?"],"kw":["relatorio","metricas","seo","mensal"],"answer":"Sim. Em planos contínuos, enviamos relatório mensal com posições, tráfego, palavras-chave e ações realizadas."},{"id":"port_001","cat":"portal","area":"portal","type":"qa","priority":560,"q":"O que é um portal de notícias?","aliases":["portal de noticias","site de noticias","jornal online","O que é um portal de notícias?","Explique sobre O que é um portal de notícias?","Tenho dúvida: o que é um portal de notícias?","Quero entender o que é um portal de notícias?","Pode me orientar sobre o que é um portal de notícias??","Me fale sobre o que é um portal de notícias?","No caso de o que é um portal de notícias?, como funciona?","Resumo sobre o que é um portal de notícias?"],"kw":["portal","noticias","jornal","magazine"],"answer":"Site estruturado para publicação frequente de matérias, com categorias, destaques, busca, autores e SEO específico."},{"id":"port_002","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Quais recursos um portal pode ter?","aliases":["funcionalidades portal","recursos portal noticias","o que tem um portal","Quais recursos um portal pode ter?","Explique sobre Quais recursos um portal pode ter?","Tenho dúvida: quais recursos um portal pode ter?","Quero entender quais recursos um portal pode ter?","Pode me orientar sobre quais recursos um portal pode ter??","Me fale sobre quais recursos um portal pode ter?","No caso de quais recursos um portal pode ter?, como funciona?","Resumo sobre quais recursos um portal pode ter?"],"kw":["recursos","funcionalidades","portal"],"answer":"Destaques rotativos, categorias, busca interna, comentários, autores, newsletter, anúncios, áreas de últimas e mais lidas."},{"id":"port_003","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Pode integrar com Google News?","aliases":["google news","news showcase","integrar noticias google","Pode integrar com Google News?","Explique sobre Pode integrar com Google News?","Tenho dúvida: pode integrar com Google News?","Quero entender pode integrar com Google News?","Pode me orientar sobre pode integrar com Google News??","Me fale sobre pode integrar com Google News?","No caso de pode integrar com Google News?, como funciona?","Resumo sobre pode integrar com Google News?"],"kw":["google","news","showcase","noticias"],"answer":"Sim. O portal pode ser preparado conforme as diretrizes do Google Notícias. A aceitação final depende de critérios editoriais."},{"id":"port_004","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Tem área de últimas notícias?","aliases":["ultimas materias","recentes","feed de noticias","Tem área de últimas notícias?","Explique sobre Tem área de últimas notícias?","Tenho dúvida: tem área de últimas notícias?","Quero entender tem área de últimas notícias?","Pode me orientar sobre tem área de últimas notícias??","Me fale sobre tem área de últimas notícias?","No caso de tem área de últimas notícias?, como funciona?","Resumo sobre tem área de últimas notícias?"],"kw":["ultimas","recentes","feed","novidades"],"answer":"Sim. O layout inclui bloco automatizado de últimas notícias com atualização contínua."},{"id":"port_005","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Tem busca interna?","aliases":["campo de busca","procurar no site","search","Tem busca interna?","Explique sobre Tem busca interna?","Tenho dúvida: tem busca interna?","Quero entender tem busca interna?","Pode me orientar sobre tem busca interna??","Me fale sobre tem busca interna?","No caso de tem busca interna?, como funciona?","Resumo sobre tem busca interna?"],"kw":["busca","buscar","procurar","search"],"answer":"Sim. Há busca interna nativa do Blogger, com possibilidade de melhorias visuais e filtros."},{"id":"port_006","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Posso ter editoria de esporte/política/economia?","aliases":["categorias do portal","secoes","editorias","Posso ter editoria de esporte/política/economia?","Explique sobre Posso ter editoria de esporte/política/economia?","Tenho dúvida: posso ter editoria de esporte/política/economia?","Quero entender posso ter editoria de esporte/política/economia?","Pode me orientar sobre posso ter editoria de esporte/política/economia??","Me fale sobre posso ter editoria de esporte/política/economia?","No caso de posso ter editoria de esporte/política/economia?, como funciona?","Resumo sobre posso ter editoria de esporte/política/economia?"],"kw":["categorias","secoes","editorias","editoria"],"answer":"Sim. Você pode criar quantas categorias quiser (marcadores no Blogger), exibidas em menus, blocos e páginas próprias."},{"id":"port_007","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Como funciona a página de autor?","aliases":["perfil do jornalista","autor do post","assinatura","Como funciona a página de autor?","Explique sobre Como funciona a página de autor?","Tenho dúvida: como funciona a página de autor?","Quero entender como funciona a página de autor?","Pode me orientar sobre como funciona a página de autor??","Me fale sobre como funciona a página de autor?","No caso de como funciona a página de autor?, como funciona?","Resumo sobre como funciona a página de autor?"],"kw":["autor","perfil","jornalista","assinatura"],"answer":"Cada autor pode ter perfil próprio com bio, foto e listagem de posts assinados."},{"id":"port_008","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Posso ter podcast/vídeos integrados?","aliases":["embed video","spotify embed","youtube no portal","Posso ter podcast/vídeos integrados?","Explique sobre Posso ter podcast/vídeos integrados?","Tenho dúvida: posso ter podcast/vídeos integrados?","Quero entender posso ter podcast/vídeos integrados?","Pode me orientar sobre posso ter podcast/vídeos integrados??","Me fale sobre posso ter podcast/vídeos integrados?","No caso de posso ter podcast/vídeos integrados?, como funciona?","Resumo sobre posso ter podcast/vídeos integrados?"],"kw":["video","podcast","spotify","youtube","embed"],"answer":"Sim. Suportamos embeds de YouTube, Spotify e outros players de mídia."},{"id":"port_009","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Como funcionam os destaques?","aliases":["carrossel","slider de destaques","manchete","Como funcionam os destaques?","Explique sobre Como funcionam os destaques?","Tenho dúvida: como funcionam os destaques?","Quero entender como funcionam os destaques?","Pode me orientar sobre como funcionam os destaques??","Me fale sobre como funcionam os destaques?","No caso de como funcionam os destaques?, como funciona?","Resumo sobre como funcionam os destaques?"],"kw":["destaques","manchete","carrossel","slider"],"answer":"Os destaques são posts marcados com label específica e exibidos em carrossel ou bloco visual na home."},{"id":"port_010","cat":"personalizacao","area":"portal","type":"qa","priority":520,"q":"É possível ter modo escuro?","aliases":["dark mode","tema escuro","modo noite","É possível ter modo escuro?","Explique sobre É possível ter modo escuro?","Tenho dúvida: é possível ter modo escuro?","Quero entender é possível ter modo escuro?","Pode me orientar sobre é possível ter modo escuro??","Me fale sobre é possível ter modo escuro?","No caso de é possível ter modo escuro?, como funciona?","Resumo sobre é possível ter modo escuro?"],"kw":["dark","escuro","noite","tema"],"answer":"Sim. Implementamos toggle de modo escuro persistido por preferência do usuário."},{"id":"port_011","cat":"portal","area":"portal","type":"qa","priority":560,"q":"O portal aceita conteúdo em vários idiomas?","aliases":["multi idioma","multilingue","traduzido","O portal aceita conteúdo em vários idiomas?","Explique sobre O portal aceita conteúdo em vários idiomas?","Tenho dúvida: o portal aceita conteúdo em vários idiomas?","Quero entender o portal aceita conteúdo em vários idiomas?","Pode me orientar sobre o portal aceita conteúdo em vários idiomas??","Me fale sobre o portal aceita conteúdo em vários idiomas?","No caso de o portal aceita conteúdo em vários idiomas?, como funciona?","Resumo sobre o portal aceita conteúdo em vários idiomas?"],"kw":["idioma","idiomas","multilingue","traducao"],"answer":"Sim. É possível estruturar versões por idioma com hreflang adequado."},{"id":"port_012","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Posso ter área restrita?","aliases":["login","area de membros","conteudo pago","Posso ter área restrita?","Explique sobre Posso ter área restrita?","Tenho dúvida: posso ter área restrita?","Quero entender posso ter área restrita?","Pode me orientar sobre posso ter área restrita??","Me fale sobre posso ter área restrita?","No caso de posso ter área restrita?, como funciona?","Resumo sobre posso ter área restrita?"],"kw":["restrita","login","membros","assinante","pago"],"answer":"Blogger não tem login nativo de assinantes. Para área restrita, usamos soluções externas (ex.: Patreon, Memberful) integradas ao portal."},{"id":"port_013","cat":"performance","area":"portal","type":"qa","priority":520,"q":"Quantas matérias o portal aguenta?","aliases":["limite materias","quantidade posts","escalabilidade","Quantas matérias o portal aguenta?","Explique sobre Quantas matérias o portal aguenta?","Tenho dúvida: quantas matérias o portal aguenta?","Quero entender quantas matérias o portal aguenta?","Pode me orientar sobre quantas matérias o portal aguenta??","Me fale sobre quantas matérias o portal aguenta?","No caso de quantas matérias o portal aguenta?, como funciona?","Resumo sobre quantas matérias o portal aguenta?"],"kw":["aguenta","limite","quantidade","escala"],"answer":"O Blogger comporta dezenas de milhares de posts sem perda de performance, por ser hospedado no Google."},{"id":"port_014","cat":"portal","area":"portal","type":"qa","priority":560,"q":"O portal tem comentários?","aliases":["comentarios no portal","interagir nas materias","O portal tem comentários?","Explique sobre O portal tem comentários?","Tenho dúvida: o portal tem comentários?","Quero entender o portal tem comentários?","Pode me orientar sobre o portal tem comentários??","Me fale sobre o portal tem comentários?","No caso de o portal tem comentários?, como funciona?","Resumo sobre o portal tem comentários?"],"kw":["comentarios","interagir","discussao"],"answer":"Sim. Pode usar o sistema nativo do Blogger, Disqus ou Facebook Comments."},{"id":"port_015","cat":"portal","area":"portal","type":"qa","priority":560,"q":"Tem integração com RSS?","aliases":["feed rss","assinar feed","rss reader","Tem integração com RSS?","Explique sobre Tem integração com RSS?","Tenho dúvida: tem integração com RSS?","Quero entender tem integração com RSS?","Pode me orientar sobre tem integração com RSS??","Me fale sobre tem integração com RSS?","No caso de tem integração com RSS?, como funciona?","Resumo sobre tem integração com RSS?"],"kw":["rss","feed","assinar"],"answer":"Sim. Blogger gera feed RSS/Atom nativamente para que leitores e agregadores acompanhem o portal."},{"id":"supo_001","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Como funciona o suporte?","aliases":["canal de suporte","atendimento tecnico","pedir suporte","Como funciona o suporte?","Explique sobre Como funciona o suporte?","Tenho dúvida: como funciona o suporte?","Quero entender como funciona o suporte?","Pode me orientar sobre como funciona o suporte??","Me fale sobre como funciona o suporte?","No caso de como funciona o suporte?, como funciona?","Resumo sobre como funciona o suporte?"],"kw":["suporte","atendimento","tecnico","ajuda"],"answer":"O suporte é feito por canal direto (e-mail ou WhatsApp) em horário comercial. Clientes ativos têm prioridade."},{"id":"supo_002","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Meu site saiu do ar, o que faço?","aliases":["site fora do ar","site nao abre","problema no site","Meu site saiu do ar, o que faço?","Explique sobre Meu site saiu do ar, o que faço?","Tenho dúvida: meu site saiu do ar, o que faço?","Quero entender meu site saiu do ar, o que faço?","Pode me orientar sobre meu site saiu do ar, o que faço??","Me fale sobre meu site saiu do ar, o que faço?","No caso de meu site saiu do ar, o que faço?, como funciona?","Resumo sobre meu site saiu do ar, o que faço?"],"kw":["fora","ar","abre","problema","erro"],"answer":"Verifique conexão e abra em aba anônima. Se o problema persistir, envie o link e captura de tela do erro pelo contato."},{"id":"supo_003","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Como faço backup do meu Blogger?","aliases":["exportar blogger","salvar conteudo blogger","backup blog","Como faço backup do meu Blogger?","Explique sobre Como faço backup do meu Blogger?","Tenho dúvida: como faço backup do meu Blogger?","Quero entender como faço backup do meu Blogger?","Pode me orientar sobre como faço backup do meu Blogger??","Me fale sobre como faço backup do meu Blogger?","No caso de como faço backup do meu Blogger?, como funciona?","Resumo sobre como faço backup do meu Blogger?"],"kw":["backup","exportar","salvar","copia"],"answer":"Configurações → Gerenciar blog → Fazer backup do conteúdo. Para o tema: Tema → seta ao lado de Personalizar → Fazer backup."},{"id":"supo_004","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Esqueci a senha do Blogger","aliases":["recuperar conta","perdi acesso google","Esqueci a senha do Blogger","Explique sobre Esqueci a senha do Blogger","Tenho dúvida: esqueci a senha do Blogger","Quero entender esqueci a senha do Blogger","Pode me orientar sobre esqueci a senha do Blogger?","Me fale sobre esqueci a senha do Blogger","No caso de esqueci a senha do Blogger, como funciona?","Resumo sobre esqueci a senha do Blogger"],"kw":["esqueci","senha","recuperar","acesso"],"answer":"A senha do Blogger é a senha da sua Conta Google. Recupere por accounts.google.com."},{"id":"supo_005","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"O painel está em outro idioma","aliases":["mudar idioma blogger","painel em ingles","O painel está em outro idioma","Explique sobre O painel está em outro idioma","Tenho dúvida: o painel está em outro idioma","Quero entender o painel está em outro idioma","Pode me orientar sobre o painel está em outro idioma?","Me fale sobre o painel está em outro idioma","No caso de o painel está em outro idioma, como funciona?","Resumo sobre o painel está em outro idioma"],"kw":["idioma","ingles","painel","traducao"],"answer":"Configurações → Idioma → escolha o idioma desejado. Reabra o painel."},{"id":"supo_006","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Como reportar um bug?","aliases":["relatar erro","informar problema","encontrei bug","Como reportar um bug?","Explique sobre Como reportar um bug?","Tenho dúvida: como reportar um bug?","Quero entender como reportar um bug?","Pode me orientar sobre como reportar um bug??","Me fale sobre como reportar um bug?","No caso de como reportar um bug?, como funciona?","Resumo sobre como reportar um bug?"],"kw":["bug","erro","reportar","relatar"],"answer":"Envie pelo contato a URL, o navegador usado e uma descrição do passo a passo para reproduzir o problema."},{"id":"supo_007","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Posso pedir um treinamento?","aliases":["quero aprender a usar","treinar para usar","aulas","Posso pedir um treinamento?","Explique sobre Posso pedir um treinamento?","Tenho dúvida: posso pedir um treinamento?","Quero entender posso pedir um treinamento?","Pode me orientar sobre posso pedir um treinamento??","Me fale sobre posso pedir um treinamento?","No caso de posso pedir um treinamento?, como funciona?","Resumo sobre posso pedir um treinamento?"],"kw":["treinamento","aprender","aulas","ensinar"],"answer":"Sim. Sessões de treinamento podem ser agendadas após a entrega ou contratadas avulsas."},{"id":"supo_008","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Como restaurar um post excluído?","aliases":["recuperar post apagado","desfazer exclusao","Como restaurar um post excluído?","Explique sobre Como restaurar um post excluído?","Tenho dúvida: como restaurar um post excluído?","Quero entender como restaurar um post excluído?","Pode me orientar sobre como restaurar um post excluído??","Me fale sobre como restaurar um post excluído?","No caso de como restaurar um post excluído?, como funciona?","Resumo sobre como restaurar um post excluído?"],"kw":["restaurar","recuperar","apagado","excluido","lixeira"],"answer":"Postagens excluídas vão para \"Excluído\" e podem ser restauradas em até alguns meses pelo próprio painel."},{"id":"supo_009","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Como migrar para outro template sem perder dados?","aliases":["mudar template sem perder","trocar tema com seguranca","Como migrar para outro template sem perder dados?","Explique sobre Como migrar para outro template sem perder dados?","Tenho dúvida: como migrar para outro template sem perder dados?","Quero entender como migrar para outro template sem perder dados?","Pode me orientar sobre como migrar para outro template sem perder dados??","Me fale sobre como migrar para outro template sem perder dados?","No caso de como migrar para outro template sem perder dados?, como funciona?","Resumo sobre como migrar para outro template sem perder dados?"],"kw":["migrar","template","sem","perder"],"answer":"Faça backup do tema atual e do conteúdo antes da troca. Templates afetam layout, não as postagens."},{"id":"supo_010","cat":"suporte","area":"suporte","type":"qa","priority":550,"q":"Posso desinstalar este chat?","aliases":["remover widget","tirar chat","desativar assistente","Posso desinstalar este chat?","Explique sobre Posso desinstalar este chat?","Tenho dúvida: posso desinstalar este chat?","Quero entender posso desinstalar este chat?","Pode me orientar sobre posso desinstalar este chat??","Me fale sobre posso desinstalar este chat?","No caso de posso desinstalar este chat?, como funciona?","Resumo sobre posso desinstalar este chat?"],"kw":["desinstalar","remover","tirar","desativar"],"answer":"Sim. No painel do Blogger: Layout → localize o gadget HTML/JavaScript do widget → Editar → Remover."},{"id":"cont_001","cat":"contato","area":"contato","type":"qa","priority":630,"q":"Como entro em contato?","aliases":["falar com voces","contato direto","como falar","Como entro em contato?","Explique sobre Como entro em contato?","Tenho dúvida