var SYN={zap:"whatsapp",wpp:"whatsapp",wapp:"whatsapp",orcamento:"preco",orçamento:"preco",custo:"preco",valor:"preco",custa:"preco",custar:"preco",demora:"prazo",tempo:"prazo",dias:"prazo",template:"tema",gadget:"widget",metatag:"meta",metatags:"meta",schema:"dados",jsonld:"dados",robô:"robo",bot:"assistente",ia:"inteligencia",site:"portal",noticia:"noticias",notícias:"noticias",blogspot:"blogger",urgente:"urgencia",pressa:"urgencia"};
function $(id){return document.getElementById(id)}
function norm(s){return String(s||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9\s]/g," ").replace(/\s+/g," ").trim()}
function rawTokens(s){var n=norm(s);return n?n.split(" "):[]}
function cleanTokens(s){var out=[],arr=rawTokens(s);for(var i=0;i<arr.length;i++){var t=SYN[arr[i]]||arr[i];if(t&&t.length>1&&!STOP[t]){out.push(t);if(typeof NexusV7Muscle!=="undefined"){var st=NexusV7Muscle.stem(t);if(st&&st!==t&&st.length>3&&!STOP[st])out.push(st)}}}return uniq(out)}
function uniq(arr){var o=[],m={};for(var i=0;i<arr.length;i++){if(arr[i]&&!m[arr[i]]){m[arr[i]]=1;o.push(arr[i])}}return o}
function ngrams(tokens,n){var out=[];for(var i=0;i<=tokens.length-n;i++)out.push(tokens.slice(i,i+n).join(" "));return out}
function allgrams(tokens){return uniq(tokens.concat(ngrams(tokens,2)).concat(ngrams(tokens,3)))}
function overlap(a,b){if(!a.length||!b.length)return 0;var A={},B={},all={},i,k,inter=0,uni=0;for(i=0;i<a.length;i++){A[a[i]]=1;all[a[i]]=1}for(i=0;i<b.length;i++){B[b[i]]=1;all[b[i]]=1}for(k in all){uni++;if(A[k]&&B[k])inter++}return uni?inter/uni:0}
function containsAny(n,arr){for(var i=0;i<arr.length;i++){if(n.indexOf(arr[i])>=0)return true}return false}
function editDistance(a,b){a=String(a||"");b=String(b||"");if(Math.abs(a.length-b.length)>3)return 9;var m=[],i,j;for(i=0;i<=b.length;i++)m[i]=[i];for(j=0;j<=a.length;j++)m[0][j]=j;for(i=1;i<=b.length;i++){for(j=1;j<=a.length;j++){m[i][j]=b.charAt(i-1)===a.charAt(j-1)?m[i-1][j-1]:Math.min(m[i-1][j-1]+1,m[i][j-1]+1,m[i-1][j]+1)}}return m[b.length][a.length]}
function fuzzyHit(a,b){if(typeof NexusV7Muscle!=="undefined")return NexusV7Muscle.fuzzyTokenHit(a,b);if(!a||!b||a.length<4||b.length<4)return 0;var d=editDistance(a,b),max=Math.max(a.length,b.length);return d<=2?1-d/max:0}


var NexusV7Muscle={
  version:"7.0-ultimate-engine",
  config:{stemGuard:4,fuzzyMaxDistance:2,fallbackThreshold:0.36},
  normalize:function(s){
    return String(s||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^\w\s]/g," ").replace(/\s+/g," ").trim();
  },
  stem:function(w){
    w=String(w||"").toLowerCase();
    if(w.length<=this.config.stemGuard)return w;
    return w
      .replace(/(acoes|ções)$/,"cao")
      .replace(/(mente)$/,"")
      .replace(/(ando|endo|indo)$/,"")
      .replace(/(ados|adas|idos|idas|ado|ada|ido|ida)$/,"")
      .replace(/(ismos|istas|ismo|ista)$/,"")
      .replace(/(oes|ões)$/,"ao")
      .replace(/(es|s)$/,"");
  },
  distance:function(a,b){
    a=String(a||"");b=String(b||"");
    var matrix=Array.from({length:a.length+1},function(){return Array(b.length+1).fill(0)});
    for(var i=0;i<=a.length;i++)matrix[i][0]=i;
    for(var j=0;j<=b.length;j++)matrix[0][j]=j;
    for(i=1;i<=a.length;i++){
      for(j=1;j<=b.length;j++){
        var cost=a.charAt(i-1)===b.charAt(j-1)?0:1;
        matrix[i][j]=Math.min(matrix[i-1][j]+1,matrix[i][j-1]+1,matrix[i-1][j-1]+cost);
      }
    }
    return matrix[a.length][b.length];
  },
  similarity:function(a,b){
    a=this.normalize(a);b=this.normalize(b);
    var longer=a.length>b.length?a:b,shorter=a.length>b.length?b:a;
    if(!longer.length)return 1;
    return (longer.length-this.distance(longer,shorter))/longer.length;
  },
  segment:function(text){
    var raw=String(text||"").split(/[?!.;]+/).map(function(s){return s.trim()}).filter(Boolean);
    if(raw.length<=1)return [String(text||"").trim()].filter(Boolean);
    return raw.slice(0,6);
  },
  pickResponse:function(value,seed){
    if(!Array.isArray(value))return value;
    if(!value.length)return "";
    var s=String(seed||""),h=0;
    for(var i=0;i<s.length;i++)h=((h<<5)-h)+s.charCodeAt(i)|0;
    return value[Math.abs(h)%value.length];
  },
  fuzzyTokenHit:function(a,b){
    a=this.normalize(a);b=this.normalize(b);
    if(!a||!b||a.length<4||b.length<4)return 0;
    var d=this.distance(a,b),max=Math.max(a.length,b.length);
    return d<=this.config.fuzzyMaxDistance?1-d/max:0;
  },
  candidateScore:function(ctx,e){
    if(!ctx||!e)return 0;
    var qTokens=ctx.tokens||[],doc=e.doc||[],aliases=e.nAliases||[],kw=e.nKw||[],score=0,i,j;
    if(ctx.norm&&e.nq&&ctx.norm===e.nq)score+=1.0;
    for(i=0;i<aliases.length;i++){
      if(ctx.norm===aliases[i])score+=0.85;
      else if(ctx.norm&&aliases[i]&&(ctx.norm.indexOf(aliases[i])>=0||aliases[i].indexOf(ctx.norm)>=0))score+=0.38;
    }
    var stemHits=0,fuzzyHits=0,kwHits=0;
    for(i=0;i<qTokens.length;i++){
      var qt=qTokens[i],qst=this.stem(qt);
      for(j=0;j<doc.length&&j<80;j++){
        var dt=doc[j],dst=this.stem(dt);
        if(qt===dt||qst===dst){stemHits++;break}
        var fh=this.fuzzyTokenHit(qt,dt);
        if(fh>0){fuzzyHits+=fh;break}
      }
    }
