(function(){
  if(typeof NexusContextManager==="undefined")return;

  if(!window.ContextManager || window.ContextManager===NexusContextManager){
    window.ContextManager=NexusContextManager;
  }

  try{
    Object.defineProperty(window.ContextManager,"lastEntity",{
      configurable:true,
      get:function(){try{return NexusContextManager.get().lastEntity||null}catch(e){return null}},
      set:function(v){try{var c=NexusContextManager.get();c.lastEntity=v||null;c.lastSource="manual_property";c.lastConfidence=v?0.7:0;c.updatedAt=new Date().toISOString();NexusContextManager.save(c)}catch(e){}}
    });
  }catch(e){}

  var _ctxResolve=NexusContextManager.resolve;
  NexusContextManager.resolve=function(q){
    var out=_ctxResolve.call(this,q);
    if(out&&typeof out==="object"&&Object.prototype.hasOwnProperty.call(out,"query"))return out;
    return{query:String(q||""),changed:false,entity:this.get().lastEntity||null,reason:"compat_fallback"};
  };

  NexusContextManager.resolveText=function(q){
    var r=this.resolve(q);
    return (r&&r.query)||String(q||"");
  };

  var _ctxUpdate=NexusContextManager.update;
  NexusContextManager.update=function(question,answer,entry,meta){
    // Compatibilidade com ContextManager.update(result.best.t)
    if(arguments.length===1 && typeof question==="string"){
      var fake={id:"manual_context_topic",cat:"contexto",q:question,t:question,answer:question};
      return _ctxUpdate.call(this,question,question,fake,{source:"compat_update_single_arg"});
    }
    return _ctxUpdate.call(this,question,answer,entry,meta);
  };

  window.NXWB_RESOLVE_CONTEXT=function(q){return NexusContextManager.resolve(q)};
  window.NXWB_RESOLVE_CONTEXT_TEXT=function(q){return NexusContextManager.resolveText(q)};
})();

var NexusContextLinker={
  version:"8.3-context-wire-production",
  before:function(text){
    var original=String(text||"");
    if(!original.trim()||original.trim().charAt(0)==="/")return{original:original,query:original,changed:false,entity:null,reason:"command_or_empty"};
    if(typeof NexusContextManager==="undefined")return{original:original,query:original,changed:false,entity:null,reason:"no_manager"};

    var lastEntity=(typeof ContextManager!=="undefined"&&ContextManager.lastEntity)?ContextManager.lastEntity:(NexusContextManager.get().lastEntity||null);
    var manual=original;

    // V8.3: blindagem direta no pipeline. Antes de qualquer busca, resolve pronomes pelo último sujeito conhecido.
    if(lastEntity && /\b(ele|ela|eles|elas|isso|isto|esse|essa|esses|essas|dele|dela|deles|delas|nele|nela|nisso|lá|la|ali)\b/i.test(original)){
      manual=manual
        .replace(/\b(ele|ela|eles|elas|isso|isto|esse|essa|esses|essas)\b/gi,lastEntity)
        .replace(/\b(dele|dela|deles|delas)\b/gi,"de "+lastEntity)
        .replace(/\b(nele|nela|nisso)\b/gi,"em "+lastEntity)
        .replace(/\b(lá|la|ali)\b/gi,"em "+lastEntity)
        .replace(/\s+/g," ")
        .trim();
      if(manual!==original){
        try{console.log("Nexus: Contexto resolvido -> "+manual)}catch(e){}
        return{original:original,query:manual,changed:true,entity:lastEntity,reason:"manual_pronoun_wire",context:NexusContextManager.get()};
      }
    }

    var resolved=NexusContextManager.resolve(original);
    return{
      original:original,
      query:(resolved&&resolved.query)||original,
      changed:!!(resolved&&resolved.changed),
      entity:(resolved&&resolved.entity)||lastEntity,
      reason:(resolved&&resolved.reason)||"none",
      context:(resolved&&resolved.context)||NexusContextManager.get()
    };
  },
  after:function(original,query,result){
    try{
      if(!result||!result.entry||typeof NexusContextManager==="undefined")return false;
      var e=result.entry;
      if(result.score!==undefined&&result.score<0.35)return false;
      NexusContextManager.update(query||original,e.answer||e.r||e.text||"",e,{source:"context_linker",original:original,score:result.score,intent:result.intent});
      if(e.t||e.q||e.title){
        NexusContextManager.update(e.t||e.q||e.title);
      }
      return true;
    }catch(err){return false}
  },
  explain:function(text){
    var r=this.before(text);
    return{version:this.version,original:r.original,queryFinal:r.query,changed:r.changed,entity:r.entity,reason:r.reason,lastEntity:(typeof ContextManager!=="undefined"?ContextManager.lastEntity:null)};
