    if(longer.length===0)return 1;
    var costs=[],i,j,lastValue,newValue;
    for(i=0;i<=shorter.length;i++){
      lastValue=i;
      for(j=0;j<=longer.length;j++){
        if(i===0)costs[j]=j;
        else if(j>0){
          newValue=costs[j-1];
          if(shorter.charAt(i-1)!==longer.charAt(j-1))newValue=Math.min(Math.min(newValue,lastValue),costs[j])+1;
          costs[j-1]=lastValue;
          lastValue=newValue;
        }
      }
      if(i>0)costs[longer.length]=lastValue;
    }
    return (longer.length-costs[longer.length])/parseFloat(longer.length);
  },
  phraseSimilarity:function(input,entry){
    var q=entry.q||"",best=this.similarity(input,q),aliases=entry.aliases||[];
    for(var i=0;i<aliases.length;i++)best=Math.max(best,this.similarity(input,aliases[i]));
    return best;
  },
  unanswered:function(){
    return Store.get(NXWB_CONFIG.storage.unanswered,[]);
  },
  promoteUnanswered:function(index,answer,aliases){
    var arr=this.unanswered();
    if(!arr.length)return{ok:false,error:"Não há perguntas sem resposta para promover."};
    var rawIndex=index;
    if(index==="last"||index==="ultimo"||index==="último")index=arr.length-1;
    else index=parseInt(index,10);
    if(isNaN(index))return{ok:false,error:"Índice inválido. Use 1, 2, 3... ou last."};
    if(index>0)index=index-1;
    if(index<0||index>=arr.length)return{ok:false,error:"Índice fora da lista. Total atual: "+arr.length};
    var item=arr[index],question=item.q||item.question||item.raw||"";
    if(!question)return{ok:false,error:"A pergunta selecionada não tem texto."};
    var learned=this.learn(question,answer,aliases||[]);
    if(!learned.ok)return learned;
    arr.splice(index,1);
    Store.set(NXWB_CONFIG.storage.unanswered,arr);
    learned.promotedFrom=rawIndex;
    learned.remainingUnanswered=arr.length;
    return learned;
  },
  promoteLast:function(answer,aliases){
    return this.promoteUnanswered("last",answer,aliases);
  },
  all:function(){
    return Store.get(this.key,[]);
  },
  save:function(arr){
    Store.set(this.key,(arr||[]).slice(-800));
    return true;
  },
  pruneStale:function(days){
    days=parseInt(days||30,10);
    var cutoff=Date.now()-(days*24*60*60*1000),arr=this.all(),before=arr.length,kept=[];
    for(var i=0;i<arr.length;i++){
      var e=arr[i]||{},stamp=e.lastAccessed||e.createdAt||e.added||null,keep=!!e.keep;
      if(stamp&&!keep){
        var t=Date.parse(stamp);
        if(!isNaN(t)&&t<cutoff&&(e.hits||0)===0)continue;
      }
      kept.push(e);
    }
    this.save(kept);
    try{
      var map=Store.get(this.mapKey||"nxwb_learned_brain",{}),changed=false;
      for(var key in map){
        if(!map.hasOwnProperty(key))continue;
        var m=map[key]||{},ms=m.lastAccessed||m.added||m.createdAt||null;
        if(ms){
          var mt=Date.parse(ms);
          if(!isNaN(mt)&&mt<cutoff&&(m.hits||0)===0&&!m.keep){delete map[key];changed=true;}
        }
      }
      if(changed)Store.set(this.mapKey||"nxwb_learned_brain",map);
    }catch(e){}
    return{ok:true,removed:before-kept.length,total:kept.length,days:days};
  },
  optimize:function(options){
    options=options||{};
    var days=options.days||30,max=options.max||800;
    var pr=this.pruneStale(days),arr=this.all();
    arr.sort(function(a,b){
      var ah=a.hits||0,bh=b.hits||0;
      if(bh!==ah)return bh-ah;
      return Date.parse(b.lastAccessed||b.createdAt||0)-Date.parse(a.lastAccessed||a.createdAt||0);
    });
    var before=arr.length;
    if(arr.length>max)arr=arr.slice(0,max);
    this.save(arr);
    return{ok:true,staleRemoved:pr.removed,trimmed:before-arr.length,total:arr.length,days:days,max:max};
  },
  learn:function(question,answer,aliases){
    question=String(question||"").trim();
    answer=String(answer||"").trim();
    if(!question||!answer)return{ok:false,error:"Informe pergunta e resposta."};
    var arr=this.all(),id="learn_"+Date.now()+"_"+Math.random().toString(36).slice(2,7);
    arr.push({id:id,q:question,a:answer,aliases:aliases||[],nq:this.normalize(question),createdAt:new Date().toISOString(),lastAccessed:null,hits:0,qualityScore:0});
    this.save(arr);
    return{ok:true,id:id,total:arr.length,question:question};
  },
  remove:function(idOrQuestion){
    var n=this.normalize(idOrQuestion),arr=this.all(),before=arr.length;
    arr=arr.filter(function(e){return e.id!==idOrQuestion&&String(e.q||"").toLowerCase()!==String(idOrQuestion||"").toLowerCase()&&e.nq!==n});
    this.save(arr);
    return{ok:true,removed:before-arr.length,total:arr.length};
  },
  clear:function(){
    this.save([]);
    return{ok:true,total:0};
  },
  score:function(input,entry){
    var ni=this.normalize(input),nq=entry.nq||this.normalize(entry.q),it=this.tokens(input),qt=this.tokens(entry.q),score=0,i,j;
    var sim=this.phraseSimilarity(input,entry);if(sim>=0.92)score+=9.5;else if(sim>=0.84)score+=7.5;else if(sim>=0.76)score+=5.2;
    if(ni===nq)score+=10;
    if(ni.indexOf(nq)>=0||nq.indexOf(ni)>=0)score+=7;
    var aliases=entry.aliases||[];
    for(i=0;i<aliases.length;i++){
      var na=this.normalize(aliases[i]);
      if(ni===na)score+=8;
      else if(ni.indexOf(na)>=0||na.indexOf(ni)>=0)score+=5;
    }
    var hits=0;
    for(i=0;i<qt.length;i++){
      if(it.indexOf(qt[i])>=0)hits++;
      else{
        for(j=0;j<it.length;j++){
          var d=this.distance(it[j],qt[i]);
          if(d<=2){hits+=0.72;break}
        }
      }
    }
    score+=(hits/Math.max(qt.length,1))*6;
    if((entry.hits||0)>0)score+=Math.min(1.2,entry.hits*.08);
    if(typeof NexusFeedbackBrain!=="undefined")score+=NexusFeedbackBrain.score({id:entry.id,q:entry.q,cat:"aprendido"});
    return score;
  },
  ask:function(input){
    var arr=this.all();
    if(!arr.length)return null;
    var best=null,bscore=0;
    for(var i=0;i<arr.length;i++){
      var s=this.score(input,arr[i]);
      if(s>bscore){bscore=s;best=arr[i]}
    }
    if(best&&bscore>=4.75){
      best.hits=(best.hits||0)+1;best.lastAccessed=new Date().toISOString();
      this.save(arr);
      return{entry:{id:best.id,cat:"aprendido",q:best.q,answer:best.a},score:bscore,intent:"learned",suggestions:["Ensinar outra resposta","O que você faz?","/aprendidos"]};
    }
    return null;
  },
  export:function(){
    return this.all();
  },
  stats:function(){
    var arr=this.all();
    return{version:this.version,total:arr.length,last:arr.length?arr[arr.length-1]:null};
  }
};


/* NEXUS_V6_5_LEARNING_COMPAT_LAYER */
(function(){
  if(typeof NexusLearningBrain==="undefined")return;

  NexusLearningBrain.mapKey = "nxwb_learned_brain";

  NexusLearningBrain.editDistance = function(s1,s2){
    return this.distance(this.normalize(s1),this.normalize(s2));
  };

  NexusLearningBrain.data = function(){
    var map = Store.get(this.mapKey,{});
    var arr = this.all ? this.all() : [];
    for(var i=0;i<arr.length;i++){
      var e = arr[i] || {};
      var key = this.normalize(e.q || e.question || "");
      if(key && !map[key]){
        map[key] = {
          answer: e.a || e.answer || "",
          aliases: e.aliases || [],
          added: e.createdAt || e.added || new Date().toISOString(),
          lastAccessed:e.lastAccessed||null,
          hits:e.hits||0,
          id: e.id || key
        };
      }
    }
    return map;
  };

  NexusLearningBrain.exportMap = function(){
    return this.data();
  };

  NexusLearningBrain.find = function(input){
    input = String(input||"");if(typeof NexusContextManager!=="undefined"){var v8=NexusContextManager.resolve(input);if(v8&&v8.changed)input=v8.query;}
    var inputNorm = this.normalize(input);
    if(!inputNorm)return null;

    var learned = this.ask ? this.ask(input) : null;
    if(learned && learned.entry && learned.entry.answer)return learned.entry.answer;

    var brain = this.data();
    if(brain[inputNorm] && brain[inputNorm].answer){brain[inputNorm].hits=(brain[inputNorm].hits||0)+1;brain[inputNorm].lastAccessed=new Date().toISOString();Store.set(this.mapKey,brain);return brain[inputNorm].answer;}

    var bestKey = null, bestScore = 0;
    for(var key in brain){
      if(!brain.hasOwnProperty(key))continue;
      var s = this.similarity ? this.similarity(inputNorm,key) : 0;
      var aliases = brain[key].aliases || [];
      for(var i=0;i<aliases.length;i++){
        s = Math.max(s, this.similarity ? this.similarity(inputNorm,this.normalize(aliases[i])) : 0);
      }
      if(s > bestScore){
        bestScore = s;
        bestKey = key;
      }
    }
    if(bestKey && bestScore >= 0.80 && brain[bestKey] && brain[bestKey].answer){
      brain[bestKey].hits=(brain[bestKey].hits||0)+1;brain[bestKey].lastAccessed=new Date().toISOString();Store.set(this.mapKey,brain);
      return brain[bestKey].answer;
    }
    return null;
  };

  var _oldLearn = NexusLearningBrain.learn;
  NexusLearningBrain.learn = function(q,a,aliases){
    var result = _oldLearn.call(this,q,a,aliases||[]);
    if(result && result.ok){
      var brain = Store.get(this.mapKey,{});
      brain[this.normalize(q)] = {
        answer: String(a||""),
        aliases: aliases || [],
        added: new Date().toISOString(),
        lastAccessed:null,
        hits:0,
        id: result.id || this.normalize(q)
      };
      Store.set(this.mapKey,brain);
    }
    return result;
  };

  var _oldRemove = NexusLearningBrain.remove;
  NexusLearningBrain.remove = function(idOrQuestion){
    var result = _oldRemove.call(this,idOrQuestion);
    var brain = Store.get(this.mapKey,{});
    var n = this.normalize(idOrQuestion);
    if(brain[n])delete brain[n];
    for(var key in brain){
      if(!brain.hasOwnProperty(key))continue;
      if(brain[key] && (brain[key].id===idOrQuestion || this.normalize(key)===n)){
        delete brain[key];
      }
    }
    Store.set(this.mapKey,brain);
    return result;
  };

  var _oldClear = NexusLearningBrain.clear;
  NexusLearningBrain.clear = function(){
    Store.set(this.mapKey,{});
    return _oldClear.call(this);
  };
})();


(function(){
  if(typeof NexusLearningBrain==="undefined")return;
  NexusLearningBrain.importBulk=function(items){
    if(!items)return{ok:false,error:"Envie uma lista de itens."};
    if(typeof items==="string"){
      try{items=JSON.parse(items)}catch(e){return{ok:false,error:"JSON inválido."}}
    }
    if(!Array.isArray(items))return{ok:false,error:"O conteúdo precisa ser um array."};
    var ok=0,fail=0,ids=[];
    for(var i=0;i<items.length;i++){
      var it=items[i]||{},q,a,aliases=[];
      if(Array.isArray(it)){q=it[0];a=it[1];aliases=it[2]||[]}
      else{q=it.q||it.question||it.pergunta||it.key;a=it.a||it.answer||it.resposta||it.value;aliases=it.aliases||it.sinonimos||[]}
      var r=this.learn(q,a,aliases);
      if(r&&r.ok){ok++;ids.push(r.id)}else fail++;
    }
    return{ok:true,imported:ok,failed:fail,total:this.stats().total,ids:ids.slice(-10)};
  };
})();

var NexusContextResolver={
  enrich:function(q){
    try{
      var ctx=Context.get(),n=(typeof NexusCharacterBrain!=="undefined"?NexusCharacterBrain.normalize(q):String(q||"").toLowerCase());
      if(!ctx||!ctx.lastTopic)return q;
      if(/^(e\s+)?(o\s+)?(preco|preço|valor|prazo|tempo|custo|onde|como|por que|porque|ele|ela|isso|esse|essa)\??$/.test(n)){
        return q+" sobre "+ctx.lastTopic;
      }
      if((n.indexOf("ele ")>=0||n.indexOf("ela ")>=0||n.indexOf("isso ")>=0)&&ctx.lastTopic){
        return q+" ("+ctx.lastTopic+")";
      }
    }catch(e){}
    return q;
  }
};

