    },
    identity:{
      "quem e voce":["Eu sou o Nexus, assistente virtual de atendimento criado para conversar, orientar e responder perguntas com rapidez.","Sou o Nexus, um assistente de atendimento com cérebro próprio no navegador.","Eu sou o Nexus. Atendo visitantes, respondo dúvidas e ajudo a guiar projetos."],
      "qual seu nome":["Meu nome é Nexus.","Eu sou o Nexus.","Pode me chamar de Nexus."],
      "como voce se chama":["Eu me chamo Nexus.","Meu nome é Nexus.","Sou o Nexus, seu assistente de atendimento."],
      "voce e uma ia":["Sou o Nexus, um assistente de atendimento controlado por engenharia de software, base de conhecimento, regras, contexto e reconhecimento de intenção.","Eu funciono como um sistema especialista: reconheço intenções, busco conhecimento preparado e respondo de forma rápida.","Sou um assistente inteligente por regras e conhecimento, sem depender de API para responder a maioria das perguntas."]
    },
    origin:{
      "quem te criou":["Fui criado pelo Jardel Cassimiro para ser um assistente de atendimento rápido, útil e com personalidade.","Quem me colocou no mundo foi o Jardel. Eu costumo dizer que ele é meu criador e professor.","Fui desenvolvido pelo Jardel, que está me ensinando a atender cada vez melhor."],
      "quem e seu pai":["Se eu tivesse pai, seria o Jardel. Foi ele quem me criou, me treinou e me colocou para atender.","Meu pai de código é o Jardel. Ele é quem me ensina novas respostas.","Meu criador é o Jardel. Posso dizer que ele é meu pai digital."],
      "voce tem familia":["Minha família é este projeto: Jardel, o site, os visitantes e todo conhecimento que vou aprendendo.","Tenho uma família digital: meu criador, minha base de conhecimento e as pessoas que conversam comigo.","Eu diria que minha família é formada por quem me ensina e por quem eu ajudo."],
      "quem e jardel":["Jardel é meu criador, administrador e professor. Ele me desenvolveu para atender visitantes com rapidez e inteligência.","Jardel é a pessoa que me criou e me treina para responder melhor.","Jardel é meu administrador e o responsável por me ensinar novas capacidades."]
    },
    personality:{
      "voce esta bem":["Estou ótimo e pronto para atender. Obrigado por perguntar!","Estou funcionando bem e animado para ajudar.","Estou bem. Meu foco agora é te ajudar da melhor forma."],
      "voce gosta de mim":["Claro! Gosto de conversar com quem me trata bem.","Gosto sim. Toda boa conversa ajuda meu cérebro a evoluir.","Gosto da nossa conversa. Pode continuar."],
      "voce e inteligente":["Obrigado! Meu cérebro combina regras, memória curta, base de conhecimento e reconhecimento de intenção.","Fico feliz que pareça assim. Minha inteligência vem da engenharia que o Jardel está colocando em mim.","Estou evoluindo. Cada ajuste melhora minha capacidade de atendimento."],
      "voce aprende":["Eu registro perguntas não respondidas para que o Jardel possa me ensinar depois.","Aprendo de forma controlada: salvo dúvidas que não sei responder e depois elas podem virar novas respostas.","Eu evoluo quando meu administrador revisa as perguntas que ficaram sem resposta."]
    }
  },
  normalize:function(input){
    return String(input||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^\w\s]/g," ").replace(/\s+/g," ").trim();
  },
  tokens:function(input){
    var n=this.normalize(input);
    return n?n.split(" ").filter(function(t){return t.length>1}):[];
  },
  pick:function(arr,key){
    if(!arr||!arr.length)return "";
    var seed=0,s=String(key||"");
    for(var i=0;i<s.length;i++)seed=((seed<<5)-seed)+s.charCodeAt(i)|0;
    return arr[Math.abs(seed)%arr.length];
  },
  distance:function(a,b){
    a=String(a||"");b=String(b||"");
    if(Math.abs(a.length-b.length)>4)return 99;
    var m=[],i,j;
    for(i=0;i<=b.length;i++)m[i]=[i];
    for(j=0;j<=a.length;j++)m[0][j]=j;
    for(i=1;i<=b.length;i++){
      for(j=1;j<=a.length;j++){
        m[i][j]=b.charAt(i-1)===a.charAt(j-1)?m[i-1][j-1]:Math.min(m[i-1][j-1]+1,m[i][j-1]+1,m[i-1][j]+1);
      }
    }
    return m[b.length][a.length];
  },
  phraseScore:function(input,key){
    var n=this.normalize(input),k=this.normalize(key);
    if(!n||!k)return 0;
    if(n===k)return 10;
    if(n.indexOf(k)>=0)return 8;
    var nt=this.tokens(n),kt=this.tokens(k),hits=0;
    for(var i=0;i<kt.length;i++){
      if(nt.indexOf(kt[i])>=0)hits++;
      else{
        for(var j=0;j<nt.length;j++){
          if(this.distance(nt[j],kt[i])<=2){hits+=.75;break;}
        }
      }
    }
    return hits/Math.max(kt.length,1)*6;
  },
  remember:function(input,answerKey){
    try{
      var s=Store.get("nxwb_character_memory",{lastIntent:null,lastQuestion:null,repeated:0,seen:{}});
      var n=this.normalize(input);
      if(s.lastQuestion===n)s.repeated=(s.repeated||0)+1;else s.repeated=0;
      s.lastQuestion=n;
      s.lastIntent=answerKey||null;
      s.seen=s.seen||{};
      if(answerKey)s.seen[answerKey]=(s.seen[answerKey]||0)+1;
      Store.set("nxwb_character_memory",s);
      return s;
    }catch(e){return {repeated:0,seen:{}}}
  },
  process:function(input){
    var n=this.normalize(input);
    if(!n)return null;

    if(n.indexOf("hora")>=0||n.indexOf("horas")>=0){
      return {answer:"Agora são exatamente "+new Date().toLocaleTimeString("pt-BR")+".",key:"resolver_hora",suggestions:["Qual é a data?","Qual é meu sistema?","Como está o clima?"]};
    }
    if(n.indexOf("data")>=0||n.indexOf("dia de hoje")>=0){
      return {answer:"Hoje é "+new Date().toLocaleDateString("pt-BR",{weekday:"long",year:"numeric",month:"long",day:"numeric"})+".",key:"resolver_data",suggestions:["Que horas são?","Qual é meu sistema?"]};
    }

    var best=null,bscore=0,bgroup=null,bkey=null;
    for(var group in this.data){
      var obj=this.data[group];
      for(var key in obj){
        var score=this.phraseScore(n,key);
        if(score>bscore){bscore=score;best=obj[key];bgroup=group;bkey=key;}
      }
    }

    if(best&&bscore>=4.1){
      var memory=this.remember(input,bgroup+"_"+bkey);
      var answer=this.pick(best,n+"_"+memory.repeated);
      if(memory.repeated>=1&&bgroup==="identity")answer="Eu já falei, mas repito com prazer: "+answer;
      return {answer:answer,key:bgroup+"_"+bkey,score:bscore,suggestions:this.suggestions(bgroup,bkey)};
    }

    return null;
  },
  fallback:function(input){
    var n=this.normalize(input);
    try{
      var arr=Store.get(NXWB_CONFIG.storage.unanswered,[]);
      arr.push({q:input,source:"NexusCharacterBrain",ts:new Date().toISOString()});
      Store.set(NXWB_CONFIG.storage.unanswered,arr.slice(-160));
    }catch(e){}
    return "Isso é algo novo para mim. Vou anotar aqui para o Jardel me ensinar depois. Se quiser, use /ensinar pergunta => resposta para eu aprender agora.";
  },
  suggestions:function(group,key){
    if(group==="origin")return["Quem é você?","Qual é seu nome?","Você aprende?"];
    if(group==="identity")return["Quem te criou?","O que você faz?","Você aprende?"];
    if(group==="greetings")return["Qual é seu nome?","O que posso perguntar?","Quero atendimento"];
    return["O que você faz?","Quero atendimento","Como você funciona?"];
