var WikiSearch={
  version:"7.1-wiki-optin",
  lang:"pt",
  timeout:5000,
  cache:{},
  blockedCats:["preco","prazo","contato","lead","suporte","servicos","whatsapp","email","manutencao"],
  blockedWords:["preco","preço","valor","custo","quanto custa","orcamento","orçamento","prazo","demora","entrega","whatsapp","zap","email","e-mail","contato","telefone","contratar","servico","serviço","servicos","serviços","suporte","manutencao","manutenção","lead"],
  minScore:0.35,
  clean:function(q){
    return String(q||"").replace(/^\/wiki\s+/i,"").replace(/^buscar\s+na\s+wikipedia\s*:?\s*/i,"").trim();
  },
  sanitizeHTML:function(html){
    try{
