    }
  },
  isBusiness:function(text,res){
    var n=norm(text),intent=norm((res&&res.intent)||""),cat=norm((res&&res.entry&&res.entry.cat)||"");
    if(this.blockedCats.indexOf(intent)>=0||this.blockedCats.indexOf(cat)>=0)return true;
    if(res&&res.entry&&(res.entry.lead||res.entry.contact))return true;
    return containsAny(n,this.blockedWords);
  },
  shouldOffer:function(text,res){
    if(!text||String(text).trim().charAt(0)==="/")return false;
    if(this.isBusiness(text,res))return false;
    var score=(res&&typeof res.score==="number")?res.score:0;
    if(score>=this.minScore)return false;
    var n=norm(text);
    if(n.length<4)return false;
    return true;
  },
  timeoutFetch:function(url,ms){
    var ctrl=null,timer=null;
    if(window.AbortController){
      ctrl=new AbortController();
      timer=setTimeout(function(){try{ctrl.abort()}catch(e){}},ms||this.timeout);
    }
    return fetch(url,{signal:ctrl?ctrl.signal:void 0}).then(function(r){
      if(timer)clearTimeout(timer);
