      return r.json();
    });
  },
  search:function(query){
    var q=this.clean(query),self=this;var v8=(typeof NexusContextManager!=="undefined")?NexusContextManager.resolve(q):{query:q,changed:false};q=v8.query||q;
    if(!q)return Promise.resolve({found:false,text:"Digite um termo para pesquisar na Wikipedia.",links:[],suggestions:[]});
