      var snippet=self.sanitizeHTML(results[0].snippet||"");
      var extractUrl="https://"+self.lang+".wikipedia.org/w/api.php?action=query&prop=extracts&exintro=1&explaintext=1&redirects=1&titles="+encodeURIComponent(title)+"&format=json&origin=*";
      return self.timeoutFetch(extractUrl,self.timeout).then(function(d2){
        var pages=(d2&&d2.query&&d2.query.pages)||{},pid=Object.keys(pages)[0],page=pages[pid]||{};
        var finalTitle=page.title||title;
        var extract=self.sanitizeHTML(page.extract||snippet||"");
        var first=extract.split(/\n+/).filter(Boolean)[0]||extract;
        if(first.length>720)first=first.slice(0,717)+"...";
        var link="https://"+self.lang+".wikipedia.org/wiki/"+encodeURIComponent(String(finalTitle).replace(/\s+/g,"_"));
        var out={found:true,title:finalTitle,text:"Segundo a Wikipedia, "+first,links:[{title:"Ver artigo completo",url:link}],suggestions:["/wiki "+finalTitle,"O que posso perguntar?","/pendentes"]};
        self.cache[key]=out;
        return out;
      });
    }).catch(function(err){
