      self.cache[key]=out;
      return out;
    });
  },
  status:function(){
    return{version:this.version,lang:this.lang,timeout:this.timeout,cache:Object.keys(this.cache).length,minScore:this.minScore,alwaysAvailable:true,optIn:true,providers:["Wikipedia"]};
  }
