var NexusPersona={
  key:"nxwb_persona_v68",
  defaultMood:"auto",
  get:function(){
    return Store.get(this.key,{mood:this.defaultMood,signature:true,auto:true,createdAt:new Date().toISOString()});
  },
  set:function(mood){
    mood=this.normalizeMood(mood);
    var cfg=this.get();
    cfg.mood=mood;
    cfg.auto=(mood==="auto");
    cfg.updatedAt=new Date().toISOString();
    Store.set(this.key,cfg);
    return{ok:true,mood:mood,activeMood:this.activeMood(),config:cfg};
  },
  normalizeMood:function(mood){
    mood=String(mood||"auto").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").trim();
    var allowed={auto:1,profissional:1,amigavel:1,descontraido:1,mentor:1,comercial:1,direto:1};
    return allowed[mood]?mood:"auto";
  },
  activeMood:function(){
    var cfg=this.get(),m=cfg.mood||"auto";
    if(m!=="auto")return m;
    var h=(new Date()).getHours();
    if(h>=8&&h<18)return"profissional";
    if(h>=18&&h<22)return"amigavel";
    return"direto";
  },
  shouldApply:function(text,meta){
    text=String(text||"").trim();
    if(!text)return false;
    if(meta&&meta.noPersona)return false;
    if(text.charAt(0)==="{"||text.charAt(0)==="[")return false;
    if(/^Comandos:/i.test(text))return false;
    if(/^Pong\./i.test(text))return false;
    if(/^XML|^JS|^Exportei|^Importa|^Memória|^Base|^Feedback|^Contexto|^Promovido|^Removi|^Autolimpeza|^Self-pruning|^Otimização/i.test(text))return false;
    if(text.length<12)return false;
    return true;
  },
  alreadyStyled:function(text){
    return /\b(Nexus por aqui|Conte comigo|posso te guiar|vamos resolver|seguimos juntos)\b/i.test(text);
  },
  apply:function(answer,meta){
    var txt=String(answer||"").trim();
    if(!this.shouldApply(txt,meta)||this.alreadyStyled(txt))return txt;
    var mood=this.activeMood();
    if(mood==="direto")return this.direct(txt,meta);
    if(mood==="profissional")return this.professional(txt,meta);
    if(mood==="amigavel")return this.friendly(txt,meta);
    if(mood==="descontraido")return this.casual(txt,meta);
    if(mood==="mentor")return this.mentor(txt,meta);
    if(mood==="comercial")return this.commercial(txt,meta);
    return txt;
  },
  direct:function(txt){return txt;},
  professional:function(txt,meta){
    if(/^Claro\.|^Perfeito\.|^Entendi\./i.test(txt))return txt;
    if(meta&&(meta.intent==="preco"||meta.cat==="preco"))return"Perfeito. "+txt;
    if(meta&&(meta.intent==="prazo"||meta.cat==="prazo"))return"Entendi. "+txt;
    return txt;
  },
  friendly:function(txt,meta){
    if(/^Olá!|^Oi!|^Perfeito\.|^Claro\./i.test(txt))return txt;
    if(meta&&meta.cat==="identidade")return txt;
    return"Claro. "+txt+" Conte comigo.";
  },
  casual:function(txt,meta){
    if(meta&&(meta.cat==="privacidade"||meta.cat==="seguranca"))return txt;
    if(/^Boa|^Bom|^Olá|^Oi/i.test(txt))return txt;
    return txt+" 😉";
  },
  mentor:function(txt,meta){
    if(/^Vamos por partes:/i.test(txt))return txt;
    if(meta&&(meta.intent==="learned"||meta.cat==="aprendido"))return"Vamos por partes: "+txt;
    if(meta&&(meta.cat==="seo"||meta.cat==="blogger"||meta.cat==="portal"))return"Vamos por partes: "+txt;
    return txt;
  },
  commercial:function(txt,meta){
    if(meta&&(meta.intent==="contato"||meta.intent==="lead"||meta.cat==="contato"||meta.cat==="preco"))return txt+" Posso transformar isso em um próximo passo de atendimento para você.";
    return txt;
  },
  status:function(){
    var cfg=this.get();
    return{version:"6.8-persona-engine",configuredMood:cfg.mood,activeMood:this.activeMood(),auto:!!cfg.auto,available:["auto","profissional","amigavel","descontraido","mentor","comercial","direto"]};
  }
};

var Robot={img:null,ready:false,timer:null,canvas:null,ctx:null,fab:null,fabCtx:null,init:function(){this.canvas=$("nxwb-robot-canvas");this.fab=$("nxwb-fab-canvas");if(!this.canvas||!this.fab)return;this.ctx=this.canvas.getContext("2d");this.fabCtx=this.fab.getContext("2d");this.img=new Image();var s=this;this.img.onload=function(){s.ready=true;s.idle()};this.img.src=NXWB_CONFIG.robot.spriteUrl},draw:function(f){if(!this.ready)return;var c=NXWB_CONFIG.robot,col=f%c.cols,row=Math.floor(f/c.cols);this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height);this.ctx.drawImage(this.img,col*c.frameWidth,row*c.frameHeight,c.frameWidth,c.frameHeight,0,0,this.canvas.width,this.canvas.height);this.fabCtx.clearRect(0,0,this.fab.width,this.fab.height);this.fabCtx.drawImage(this.img,col*c.frameWidth,row*c.frameHeight,c.frameWidth,c.frameHeight,0,0,this.fab.width,this.fab.height)},anim:function(fr,iv,st){var s=this,i=0,stage=$("nxwb-robot-stage");clearInterval(this.timer);if(stage){stage.classList.remove("nxwb-speaking","nxwb-listening","nxwb-thinking");if(st)stage.classList.add("nxwb-"+st)}this.draw(fr[0]||0);this.timer=setInterval(function(){s.draw(fr[i%fr.length]);i++},iv||120)},idle:function(){this.anim(NXWB_CONFIG.robot.idleFrames,450,"idle")},thinking:function(){this.anim(NXWB_CONFIG.robot.thinkFrames,160,"thinking")},listening:function(){this.anim(NXWB_CONFIG.robot.listenFrames,130,"listening")},speaking:function(){this.anim(NXWB_CONFIG.robot.speakFrames,105,"speaking")},stop:function(){clearInterval(this.timer);this.idle()}};

function NXWB_STRIP_EMOJIS_FOR_SPEECH(text){
  return String(text||"")
    .replace(/[\u{1F1E6}-\u{1F1FF}]/gu,"")
    .replace(/[\u{1F300}-\u{1F5FF}]/gu,"")
    .replace(/[\u{1F600}-\u{1F64F}]/gu,"")
    .replace(/[\u{1F680}-\u{1F6FF}]/gu,"")
    .replace(/[\u{1F700}-\u{1F77F}]/gu,"")
    .replace(/[\u{1F780}-\u{1F7FF}]/gu,"")
    .replace(/[\u{1F800}-\u{1F8FF}]/gu,"")
    .replace(/[\u{1F900}-\u{1F9FF}]/gu,"")
    .replace(/[\u{1FA00}-\u{1FAFF}]/gu,"")
    .replace(/[\u{2600}-\u{27BF}]/gu,"")
    .replace(/[\u{FE00}-\u{FE0F}]/gu,"")
    .replace(/\u200D/gu,"")
    .replace(/[★☆✓✔✕✖✦✧•●○◆◇■□▲▼▶▷◀◁→←↑↓]/g,"")
    .replace(/\s+/g," ")
    .trim();
}

